window.TPP_DAILY=window.TPP_DAILY||{};window.TPP_DAILY["fours"]={"aug":{"theme":"Welcome to Our Den","weeks":[{"label":"Week 1 — Our New Den","days":[{"day":"Monday","focus":"Our Home Den","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Build a Home Den","d":"Pick a cozy corner and set it up together with a pillow, a few books, and a cup of crayons. Let your child arrange it their way — having a learning spot of their own tells them school-style learning happens at home too."},{"t":"House Tour Guide","d":"Hand your child a paper-towel-roll microphone and let them lead a tour: “This is the kitchen, this is where we read.” Naming the spaces in their world builds the confidence they'll need touring a brand-new classroom."}]},{"day":"Tuesday","focus":"Letter A Day","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Giant Tape A","d":"Make a big letter A on the floor with masking tape, then let your child walk it, hop it, and drive a toy car along it. Big-body letters stick long before pencil letters do."},{"t":"A Sound Claps","d":"Say word pairs — apple and ball, ant and cup — and have your child clap only when they hear the a sound. Hearing a letter's sound comes before reading it, and fours love catching you trying to trick them."}]},{"day":"Wednesday","focus":"Circle Science","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Roll or Slide","d":"Prop a cookie sheet on a couch cushion to make a ramp, then test things: a can, a block, a ball, a book. Round things roll and flat things slide — let your child predict before each test. That's a real experiment."},{"t":"Circle Hunt","d":"Search the kitchen for circles — plates, lids, the clock — and count how many you find. This month's shape is the circle, and spotting shapes in real life is how shape names truly stick."}]},{"day":"Thursday","focus":"Seeing Red","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Red Circle Collage","d":"Tear red bits from junk mail or old magazines and glue them inside one big drawn circle. Tearing paper builds the same finger muscles your child will use to write their name."},{"t":"Red Spotter","d":"Walk through the house or down the block spotting red things, and keep a tally together. Staying on one job — just red, nothing else — stretches the focus muscles school will ask for."}]},{"day":"Friday","focus":"Cozy and Ready","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Backpack Buddy Talk","d":"Pack a backpack together — real or pretend — and talk about what school will feel like. Ask for one excited feeling and one wiggly one; naming both makes the first day less scary."},{"t":"Den Story Time","d":"Celebrate the new home den with its very first read-together. A Bear Phonics decodable or any favorite works — let your child hold the book and turn every page, because that's what readers do."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in your pocket — small moments that make the new school year feel safe.","items":["Keep the home den sacred: five minutes there after school beats an hour of questions.","Point out the letter A on cereal boxes, signs, and mail all week.","Let your child carry one small comfort item on new-place days.","Practice the morning goodbye now: hug, kiss, high five, wave — same order every time."]}},{"label":"Week 2 — New Friends","days":[{"day":"Monday","focus":"Friendly Moves","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Roll and Greet","d":"Sit facing each other and roll a ball back and forth. Every catch, say “Hi, I'm —” with a big smile. It's playful practice for the moment they meet a brand-new classmate."},{"t":"Mirror Friend","d":"Stand face to face and take turns copying each other — slow waves, silly faces, one-foot balances. Reading another person's body is the quiet skill under every friendship."}]},{"day":"Tuesday","focus":"Letter B Buddies","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Willoughby Wallaby Names","d":"Sing the silly rhyming name song with everyone in the family — Willoughby Wallaby Wee, an elephant sat on me. Playing with names tunes the ear for letter sounds, and B gets a starring turn."},{"t":"B Basket","d":"Send your child around the house to gather things that start with B — ball, book, bear, banana. Line them up, say each word slowly, and let them feel the b bounce on their lips."}]},{"day":"Wednesday","focus":"How Many Friends","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"People Who Love Me","d":"Count the people who love your child — family, neighbors, cousins — making one tally mark each. Watching the marks pile up is counting practice and a warm little reminder all at once."},{"t":"Alike and Different","d":"Sit with a sibling or parent and compare: same eye color? Different favorite food? Finding ways we match and ways we don't is exactly how children learn everyone belongs."}]},{"day":"Thursday","focus":"Friendship Art Lab","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Family Handprints","d":"Trace every family member's hand on one big page, then compare — whose is biggest, whose is smallest? Lining them up in size order sneaks in real observation and measurement."},{"t":"Crayons Team Up","d":"Pick two crayons to be buddies — red and yellow — and layer their scribbles to discover what color they make together. Two friends working together made something brand new."}]},{"day":"Friday","focus":"Kind Words","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Practice Hello","d":"Line up the stuffed animals and rehearse first-day introductions: “Hi, I'm —. Want to play?” Practicing the words at home means they're ready when a real friend appears."},{"t":"Friend Story Time","d":"Read a story about friends together and pause to ask how the characters feel and what made them friends. Talking about a story doubles what a child takes from it."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Friendship is a skill like any other — these little reps make it easier.","items":["Rehearse one friendly opener at breakfast: “Hi, I'm —. Want to play?”","Point out the letter B on boxes, books, and buildings this week.","At pickup, ask “Who did you play with?” instead of “How was school?”","Trade one small kindness a day — a drawing, a shared snack, a thank you."]}},{"label":"Week 3 — Rules & Routines","days":[{"day":"Monday","focus":"Clean-Up Champs","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Beat the Song","d":"Play one favorite song and race to tidy the toys before it ends. A cheerful clean-up habit at home makes the classroom version feel like old news."},{"t":"Walking Feet Parade","d":"Play follow-the-leader through the house using walking feet, quiet voices, and hands to yourself — then let your child lead. Practicing school rules as a game takes the sting out of them."}]},{"day":"Tuesday","focus":"Letter C Day","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Curvy C Painting","d":"Paint or crayon big curvy Cs across a page — show your child that C is a circle that didn't quite close. Connecting new letters to a shape they know makes both stick."},{"t":"C Sound Kitchen","d":"Search the kitchen for things that start with the c sound — cup, can, carrot, cracker. Line them up and say each word slowly, letting your child hear the c kick things off."}]},{"day":"Wednesday","focus":"First, Next, Last","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Order Our Day","d":"Draw three quick pictures of the morning routine — wake up, eat, get dressed — then mix them up and let your child put them in order saying first, next, last. Sequencing is pre-reading and pre-math in one."},{"t":"Snack Steps","d":"Make a simple snack together and narrate every step in order: first the plate, next the crackers, last the cheese. Then ask your child to teach the steps back to you."}]},{"day":"Thursday","focus":"Squeaky Clean Science","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Pepper Germ Trick","d":"Sprinkle pepper on a bowl of water, then dip a soapy finger in and watch the pepper flee to the edges. That's what soap does to germs — and now hand-washing has a why."},{"t":"Scrub Song Timer","d":"Pick one song verse and make it the official hand-washing anthem — scrub tops, bottoms, and between fingers until it ends. Twenty seconds feels short when you're singing."}]},{"day":"Friday","focus":"Family Promises","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Our Home Promises","d":"Make two or three family promises together — kind words, gentle hands, we help clean up — and let your child sign their name at the bottom. Rules they help write are rules they keep."},{"t":"Calm-Down Corner","d":"Build a small calm spot with a pillow and a favorite book, then practice slow belly breaths and read a quiet story together there. Visiting it happy makes it work when feelings get big."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Routines are brain science, not busywork — a predictable rhythm actually lowers stress.","items":["Post the picture routine strip where your child can see it each morning.","Use first, next, last out loud all week — in the car, at bath time.","Sing the scrub song at every sink until it's automatic.","Revisit the family promises on Sunday and celebrate the ones you kept."]}},{"label":"Week 4 — All About School","days":[{"day":"Monday","focus":"School Skills Course","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Backpack Obstacle Course","d":"Set a playful course: zip a jacket, hang the backpack on a chair, hop to a pillow carpet spot, sit crisscross. Running the school day as a game builds real independence."},{"t":"Open It Yourself","d":"Practice the lunchtime fumbles now — opening containers, unscrewing the water bottle, peeling a banana. Every lid your child conquers at home is one less wait at the lunch table."}]},{"day":"Tuesday","focus":"All About Me","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"The Me Interview","d":"Play reporter with a spoon microphone: What's your favorite color? What makes you laugh? Write their answers down word for word and read them back — children light up hearing their own words in print."},{"t":"I Love School Because","d":"Help your child finish the sentence “I love school because...” and write it out together, letting them add the first letter of their name. Saying the good part out loud helps them believe it."}]},{"day":"Wednesday","focus":"Sort and Count","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Supply Sort","d":"Dump out the crayon bin and sort by color, then by size — long ones here, stubby ones there. Sorting by one rule, then re-sorting by another, is flexible thinking in action."},{"t":"Count the Steps","d":"Count the steps from bed to the breakfast table, then guess the steps to the front door and check. Estimating first turns plain counting into real thinking."}]},{"day":"Thursday","focus":"Five Senses Day","domains":["Scientific Inquiry","Social Studies"],"opts":[{"t":"Senses Walk","d":"Walk the house or the block collecting observations: three things you see, two you hear, one you smell. Naming what our senses catch is how scientists — and preschoolers — study the world."},{"t":"Who Helps at School","d":"Talk about the helpers your child will meet — teacher, cook, cleaner, director — and what each one does. Knowing the cast of characters makes the new place feel friendly."}]},{"day":"Friday","focus":"A-B-C Celebration","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Mirror Self-Portrait","d":"Set up a mirror and let your child draw themselves slowly — hair, eyes, that one missing tooth — then hang it proudly in the home den. Looking closely is the artist's first skill."},{"t":"A-B-C Review Read","d":"Celebrate the month: find A, B, and C on a favorite book's cover, say each sound, then read the story together. If you have the Bear Phonics reader See Me, this is its moment."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One more week of warm-ups and your four-year-old walks in like they own the place.","items":["Do a full dress rehearsal: backpack, shoes, goodbye routine, out the door.","Let your child open every container in tomorrow's lunch tonight.","Review A, B, and C sounds in the car — one letter per red light.","Frame the self-portrait; confidence loves a place of honor."]}}]},"sep":{"theme":"All About Me & My Family","weeks":[{"label":"Week 1 — This Is Me","days":[{"day":"Monday","focus":"Trace Me","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Big Body Trace","d":"Trace your child's whole body with sidewalk chalk outside, or on taped-together paper inside, then let them add the face, hair, and clothes. Seeing themselves life-size is a thrill that never gets old."},{"t":"Body Part Freeze","d":"Play music and dance, then freeze and call a body part — elbow, ankle, shoulder — for your child to touch and wiggle. Fast naming of body parts builds vocabulary and body control together."}]},{"day":"Tuesday","focus":"Super S Name","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Snake Letter S","d":"Roll play-dough or a long sock into a snake and curve it into the letter S, hissing sss as you go. S is this month's letter, and making it with hands beats tracing it on paper."},{"t":"Rainbow Name","d":"Write your child's name in big letters and let them trace over it in a different color each pass — a rainbow name. Then challenge them to write the first letter all by themselves."}]},{"day":"Wednesday","focus":"Pairs on Me","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Two of Me","d":"Explore this month's number 2 right on the body: two eyes, two ears, two hands, two feet. Then ask the puzzler — what do we have just one of? Investigating yourself is science too."},{"t":"Sock Pair Match","d":"Dump the clean-sock basket and match every pair, then count the pairs together. Matching is early math, and your laundry gets folded — everybody wins."}]},{"day":"Thursday","focus":"Proud of Me","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"My I-Can List","d":"Ask your child to name everything they can do — zip, pour, hop, help — and write the list as they talk. Hang it in the home den; on hard days, read it back to them."},{"t":"My Two Worlds","d":"Talk about the two teams your child belongs to: “I'm part of my family, and I'm part of my class.” Name their job in each one. Belonging somewhere is where confidence starts."}]},{"day":"Friday","focus":"Mirror and Story","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Mirror Talk","d":"Look in the mirror together and let your child describe what they see — curly hair, brown eyes, a big smile. Write two of their describing words on a card for the den wall."},{"t":"All About Me Book","d":"Staple three pages into a little book: my face, my family, my favorite thing. Your child draws, you label, and then read it aloud together at bedtime like a real published author."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week your child is the whole curriculum — enjoy studying them.","items":["Practice name writing on the foggy bathroom mirror after bath.","Hiss the s sound in words all week — sun, sock, soup, silly.","Count body pairs at bedtime: two eyes closing, two ears resting.","Read the I-Can List out loud any morning that starts wobbly."]}},{"label":"Week 2 — My Family","days":[{"day":"Monday","focus":"Family Puppets","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Finger Family Puppets","d":"Draw tiny family faces on paper strips and tape one around each fingertip, then sing the Where Is Thumbkin family verses. Those small finger movements are the same muscles that will hold a pencil."},{"t":"Family Photo Frame","d":"Cut a frame from a cereal box and let your child decorate it with scribble-patterns and torn paper for a favorite family photo. Art with a purpose gets extra care."}]},{"day":"Tuesday","focus":"Our Family Story","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Draw and Dictate","d":"Ask your child to draw the family doing something you all love, then write their exact words underneath and read them back, pointing to each word. Their words becoming print is reading magic."},{"t":"Family Word Clap","d":"Collect family words — grandma, cousin, sister, home — and clap the syllables in each one. Ask which words hide this month's s sound; sister hisses twice."}]},{"day":"Wednesday","focus":"Family Math","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Family Graph","d":"Stack one block or cup for each person in your family, then build a tower for grandma's family or a neighbor's. Stand them side by side and ask the big question: more, fewer, or the same?"},{"t":"Shoe Sort","d":"Pile up the family shoes and sort them by owner, then re-sort by size from biggest to smallest. Count each group — whose pile wins? Sorting two different ways is flexible pre-K thinking."}]},{"day":"Thursday","focus":"Family Science","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Doorframe Height Check","d":"Let your child predict who's tallest, then measure everyone against the doorframe with tape marks and check. Predict, test, compare — that's the whole scientific method in your hallway."},{"t":"My Family Job","d":"Give your child one real daily job — napkin setter, plant waterer, light-switch captain — and thank them for it like you mean it. Real responsibility is how belonging grows."}]},{"day":"Friday","focus":"Quilt and Stories","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Square Family Quilt","d":"Cut or tear paper into squares — this month's shape — and draw one family memory on each. Tape them together into a quilt for the den wall and let your child retell every square."},{"t":"Family Story Time","d":"Read a book about families together tonight and pause to ask who is in the story family and how they help each other. Then ask the best question: how is our family the same?"}]}],"homeden":{"title":"The Home Den — This Week","lead":"Family is your child's first classroom — this week we study the teachers.","items":["Tell one story from your own childhood at dinner; they will beg for more.","Keep the family job going daily — same job, same thank-you.","Spot squares around the house: windows, crackers, napkins.","Call or video a faraway relative and let your child do the talking."]}},{"label":"Week 3 — My Feelings","days":[{"day":"Monday","focus":"Calm Body Moves","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Smell the Flower","d":"Teach the calm-down breath: smell the flower through your nose, blow out the candle through your mouth, five slow times. Practice it giggling now so it's ready when the tears come."},{"t":"Feelings Dance","d":"Put on music and dance each feeling — mad stomps, happy hops, scared tiptoes, calm sways. Moving a feeling through the whole body helps children recognize it from the inside."}]},{"day":"Tuesday","focus":"Feelings Words","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Feelings Retell","d":"Read any storybook together and pause at the big moments: “How does she feel? How can you tell?” Retelling a story through its feelings builds comprehension and heart at the same time."},{"t":"S Is for Smile","d":"Collect feelings words that start with this month's letter — sad, silly, scared, smile, surprised — hissing the s and making each face in the mirror. Faces plus words make feelings easier to name."}]},{"day":"Wednesday","focus":"Feelings Graph","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Family Mood Graph","d":"At dinner, everyone adds a block to a happy, tired, or silly column. By Friday, count the towers and compare — which feeling won the week? Graphing real life is the best math there is."},{"t":"Body Clues Detective","d":"Play detective: where does mad live in your body — tight fists? Where does excited live — a jumpy tummy? Noticing body clues is real self-science, and it's the first step to calming down."}]},{"day":"Thursday","focus":"Helping Hearts","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"How Can We Help","d":"Act out little troubles with stuffed animals — Teddy's tower fell, Bunny feels left out — and brainstorm two ways to help each time. Rehearsed kindness shows up on the playground."},{"t":"Kindness Note","d":"Think of someone who could use some sunshine and have your child draw them a card, signing their own name. Delivering it — mailbox, doorstep, or backpack — is the best part."}]},{"day":"Friday","focus":"Feelings Art","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Orange Feelings Painting","d":"Ask what color happy is today, then scribble or paint the feeling big — this month's orange is a great place to start. Naming the feeling in the finished art turns paint into words."},{"t":"Morning Check-In Chart","d":"Make a simple feelings chart with four drawn faces and let your child point to theirs each morning. If you have Mrs. Bear's book Your Feelings Matter, it pairs perfectly with the chart."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Children who can name a feeling can start to tame it — that's the whole week.","items":["Name your own feelings out loud: “I'm frustrated, so I'm taking a breath.”","Do the flower breath together before it's needed, not just during storms.","Ask “How did that make you feel?” once a day and just listen.","Keep the check-in chart by the breakfast table all month."]}},{"label":"Week 4 — My Friends & My Class","days":[{"day":"Monday","focus":"Team Games","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Cooperative Cup Tower","d":"Build one tower together with strict turns — one cup you, one cup me — and see how tall it grows. The game only works together, which is exactly the point."},{"t":"Blanket Ball Toss","d":"Hold a blanket between you, toss a soft toy on top, and count how many bounces you can keep going — aim for ten. Two people, one goal, lots of giggles."}]},{"day":"Tuesday","focus":"Friendship Book","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Friend Pages","d":"Make one page for each friend or family member — a drawing plus one word about them that you write together. Staple it into a friendship book and read it aloud like a bedtime story."},{"t":"Play Date Invitation","d":"Let your child write an invitation to a friend or cousin — their scribbles, your translation underneath, their name signed at the bottom. Writing with a real purpose is writing that matters."}]},{"day":"Wednesday","focus":"Pattern Pals","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"AB Snack Pattern","d":"Build a snack pattern together — cracker, grape, cracker, grape — and read it aloud before eating it up. Ask what comes next before every bite; patterns are the secret handshake of math."},{"t":"Clap-Stomp Code","d":"Clap-stomp-clap-stomp a pattern and have your child copy it, then let them invent a code for you to follow. Hearing and holding a pattern trains the same brain muscles as counting."}]},{"day":"Thursday","focus":"Predict and Test","domains":["Scientific Inquiry","Social Studies"],"opts":[{"t":"Sink or Float","d":"Fill a bin with water — always within arm's reach — and gather bath toys, a spoon, a crayon. Predict before each drop, then sort the results into a sink pile and a float pile."},{"t":"Family Rules Vote","d":"Hold a family meeting and vote on one new home rule, everyone's hand counting equally. Voting together at the kitchen table is how classrooms and communities work everywhere."}]},{"day":"Friday","focus":"Celebration Friday","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"This Is Us Mural","d":"Tape big paper to the wall and let every family member add themselves to one grand portrait. Step back, admire, and title it together — your child dictates, you write."},{"t":"Compliment Circle","d":"Sit in a circle and pass compliments around — each person tells the next one something kind and true. Teach the graceful landing too: look up, smile, say thank you."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Turn-taking, patterns, and kind words — this is kindergarten readiness in disguise.","items":["Play one turn-taking game a day, even five minutes counts.","Build patterns everywhere: snacks, socks, claps at red lights.","Give one specific compliment daily: “You shared without being asked.”","End the week rereading the friendship book together."]}}]},"oct":{"theme":"The Great Outdoors","weeks":[{"label":"Week 1 — Leaves & Trees","days":[{"day":"Monday","focus":"Leaf Walk","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Crunch and Collect","d":"Take a walk and collect exactly three leaves — this month's number — stomping the crunchy ones along the way. Back home, ask which leaf is biggest, which is bendiest, which crunched loudest."},{"t":"Tree Touch Tour","d":"Visit one tree like a scientist: touch the bark, find the roots, look up the trunk to the branches and leaves. Naming a tree's parts turns the backyard into a classroom."}]},{"day":"Tuesday","focus":"Letter T Trees","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Stick Letter T","d":"Find two sticks and build the letter T on the sidewalk — one trunk standing tall, one branch across the top. T even looks like a tree, which makes this month's letter easy to love."},{"t":"T Sound Taps","d":"Say words slowly and have your child tap the table only for t words — tree, top, ten, but not sun or dog. Catching a sound by ear is the skill that unlocks reading."}]},{"day":"Wednesday","focus":"Leaf Math","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Sort and Count Leaves","d":"Spread out your leaf collection and sort by size, then by color, counting each pile. Ask which pile has more and which has fewer — real leaves make the best math counters."},{"t":"Triangle Tree Art","d":"Tear or cut paper triangles — this month's shape — and stack them into an evergreen tree, adding a brown crayon trunk for this month's color. Three triangles, one tree, lots of pride."}]},{"day":"Thursday","focus":"Park Caretakers","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Yard Helper Day","d":"Give your child a caretaker job outside — gathering sticks, watering a plant, tidying toys off the grass — while a grown-up handles any litter. Caring for shared places is a community job even fours can own."},{"t":"Thank a Park Helper","d":"Talk about the people who care for parks — mowing, planting, keeping playgrounds safe — and draw a thank-you picture together. Noticing invisible helpers grows grateful kids."}]},{"day":"Friday","focus":"Why Leaves Change","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Leaf Detective","d":"Put a green leaf and a brown leaf side by side and study them like detectives — color, feel, bendiness. Wonder aloud why leaves change: the tree is getting ready to rest for winter."},{"t":"Under-Tree Story Time","d":"Read together under a tree, or beside a window with a tree in view. The Bear Phonics reader See Me Eat Meat fits this month's letter T, but any favorite book counts."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Outdoor time is learning time — even twenty minutes of green sharpens little brains.","items":["Keep the leaf collection going all week in a shoebox museum.","Trace the letter T on backs, foggy windows, and sandy ground.","Count to three at every chance: three leaves, three steps, three hugs.","Adopt one tree near home and check on it each season."]}},{"label":"Week 2 — Bugs & Critters","days":[{"day":"Monday","focus":"Move Like Bugs","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Bug Obstacle Course","d":"Crawl like a beetle under a chair, hop like a cricket over a pillow, flutter like a butterfly to the door. Big bug moves burn energy and build the muscles pencil grips grow from."},{"t":"Gentle Watcher","d":"Find a bug outside and watch it work without touching — where is it going, what is it carrying? Practicing gentle hands with the smallest creatures grows kindness for everything bigger."}]},{"day":"Tuesday","focus":"Letter G Garden","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"G Is for Garden","d":"Write a big letter G and gather its friends out loud — garden, grass, green, go, grasshopper. Let your child trace the G with a finger, then a crayon, then in the air with eyes closed."},{"t":"Bug Word List","d":"Ask your child to name every bug they know while you write the list — ant, bee, ladybug, grasshopper. Then hand it back and let them circle any letters they recognize."}]},{"day":"Wednesday","focus":"Bug Math","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Count the Legs","d":"Study a bug picture or a real critter together: insects have six legs, spiders have eight. Count both out loud and ask the comparing question — who has more, and by how many?"},{"t":"Ladybug Dot Count","d":"Draw a few ladybugs and call out a number up to ten for your child to dot onto each back. Then flip roles and let them boss the dots while you draw."}]},{"day":"Thursday","focus":"Busy Bee Helpers","domains":["Social Studies","Scientific Inquiry"],"opts":[{"t":"Thank You, Bees","d":"Tour the kitchen finding foods bees helped make — apples, berries, cucumbers, and of course honey. Bees are tiny farmers' helpers, and knowing that changes how kids see every buzz."},{"t":"Farmer's Market Pretend","d":"Set up a pretend market with pantry items and take turns as farmer and shopper. Ask where each food really comes from — someone grew every single thing on the shelf."}]},{"day":"Friday","focus":"Bug Art and Books","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Clay Critters","d":"Build a bug from play-dough with three body parts — head, thorax, abdomen — and six dried-pasta legs. Three parts for this month's number three, and a new science word to show off."},{"t":"Itsy Bitsy Retell","d":"Read a bug book together or sing Itsy Bitsy Spider, then have your child retell it with a beginning, a middle, and an end. Retelling is the bridge between hearing stories and reading them."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Every sidewalk crack is a nature documentary this week — stop and watch.","items":["Keep a gentle-hands rule for every critter, inside and out.","Practice the g sound in the grocery store: grapes, green beans, granola.","Count legs on every bug picture you meet — six or eight?","Let your child teach someone the three insect body parts."]}},{"label":"Week 3 — Weather & Sky","days":[{"day":"Monday","focus":"Weather Moves","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Storm Dance","d":"Become the weather together — spin like wind, drum rain on your knees, boom like thunder, then freeze as the sun comes out. End with slow sunshine stretches to practice calming down after big energy."},{"t":"Puddle Jumpers","d":"Lay sock puddles across the floor and jump over each one, counting jumps to ten. Rainy days don't cancel recess when the living room becomes the storm."}]},{"day":"Tuesday","focus":"Letter J Journal","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Jumping J Words","d":"Introduce the letter J with a jump for every j word you find together — jump, jacket, jar, jelly, jet. A letter learned mid-air is a letter remembered."},{"t":"My Weather Journal","d":"Staple five pages into a weather journal and have your child draw the sky each day and write one letter or word beside it. Checking yesterday's page builds the observing habit scientists live by."}]},{"day":"Wednesday","focus":"Sky Math","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Weather Graph Week","d":"Make three columns — sunny, cloudy, rainy — and add a checkmark each day this week. On Friday, count each column and crown the winner. Which weather got more days?"},{"t":"Cloud Watch","d":"Lie back somewhere comfy and watch the clouds — are they moving fast or slow, and what shapes hide in them? The wind pushes clouds along, even when we can't feel it down here."}]},{"day":"Thursday","focus":"Weather Helpers","domains":["Social Studies","Scientific Inquiry"],"opts":[{"t":"Meteorologist Minute","d":"Check today's forecast together, then hand your child a spoon microphone to deliver their own weather report to the family. Weather helpers tell communities what's coming so everyone stays safe."},{"t":"Dress for the Weather","d":"Pull out clothes and sort them into hot-day, cold-day, and rainy-day piles, talking through why each one fits. Then let your child pick tomorrow's outfit from the right pile."}]},{"day":"Friday","focus":"Sky Art Stories","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Window Sky Painting","d":"Look out the window and draw or paint today's sky exactly as it is — the colors, the clouds, maybe a bird. Painting what you truly see, not what you imagine, is an artist's superpower."},{"t":"Rainy-Day Retell","d":"Read a weather or rainy-day book together and retell it after — what happened first, next, and last? Ask how the weather made the characters feel; stories and skies both have moods."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your junior meteorologist is on duty — expect daily forecasts at breakfast.","items":["Ask for the official weather report before choosing clothes each morning.","Jump for every letter J you spot on signs and cereal boxes.","Keep the weather journal going — five skies makes a scientist.","Count the weather graph together on Friday and announce the winner."]}},{"label":"Week 4 — Animals & Homes","days":[{"day":"Monday","focus":"Animal Moves","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Animal Parade","d":"Call out two-step moves — waddle like a duck to the couch, then hop like a frog to the door. Holding two directions in mind while moving is exactly the listening kindergarten asks for."},{"t":"Guess My Animal","d":"Act out an animal with your whole body — no sounds allowed at first — while the family guesses. Then swap. Add the sound as a hint only when the guessers are truly stuck."}]},{"day":"Tuesday","focus":"Habitat Book","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"My Habitats Book","d":"Make a page each for a nest, a den, a burrow, and a hive, and let your child draw who lives in each home while dictating a sentence for you to write. Read the finished book together, author first."},{"t":"T-G-J Animal Match","d":"Review the month's letters with animals — T for tiger, G for goat, J for jellyfish. Say each sound, then draw the silliest one. Letters stick best when they roar, bleat, and wiggle."}]},{"day":"Wednesday","focus":"Hide and Count","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Animal Home Tally","d":"Look out windows or walk the block spotting animal homes — nests, webs, holes, anthills — and tally each find. Count the tally at the end: did you beat three, this month's number?"},{"t":"Camouflage Test","d":"Hide a brown toy on brown surfaces, then on bright ones, and time how fast your child spots it each way. That's camouflage — animals wear this month's color brown to disappear."}]},{"day":"Thursday","focus":"Animal Neighbors","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Animal Map","d":"Draw a simple map together — ocean, forest, backyard — and let your child place toy animals where each one lives. Maps show where our neighbors live, even the furry and finned ones."},{"t":"Pet Care Captain","d":"Put your child in charge of caring for a real or stuffed pet today — feeding, brushing, gentle voice, cozy bed. Caring for something smaller is how big-hearted habits begin."}]},{"day":"Friday","focus":"Den Sweet Den","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Blanket Den Build","d":"Build a family den from blankets and chairs, cozy as a bear cave, and let your child design the inside — pillows here, stuffed animals there. Every architect starts somewhere."},{"t":"Flashlight Den Reading","d":"Crawl into the den with a flashlight and read together in the glow — a Bear Phonics decodable or a favorite animal story. Books read in a den get remembered forever."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Every animal has a home and a job — and so does your little one.","items":["Leave the blanket den up for one extra bedtime story.","Review T, G, and J with animal sounds in the car.","Spot animal homes on every walk — tally them together.","Keep the pet-care job going; consistency is the real lesson."]}}]},"nov":{"theme":"Thankful Hearts","weeks":[{"label":"Week 1 — I Am Thankful","days":[{"day":"Monday","focus":"Thankful Talk","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Thankful Sentence Starters","d":"At dinner, take turns finishing “I am thankful for…” — ask your child to answer in a whole sentence and add a why. Speaking in full sentences with reasons is exactly the oral language kindergarten builds on."},{"t":"Gratitude Reporter","d":"Hand your child a pretend microphone (a spoon works) and let them interview the family: “What are you thankful for?” Then swap roles. Asking and listening grow conversation skills — and you'll hear some sweet answers."}]},{"day":"Tuesday","focus":"Count Our Blessings","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Four Blessings Count","d":"Name four things you're thankful for and hold up one finger for each — four is this month's number. Then let your child draw a big 4 and decorate it. Counting on fingers connects numbers to real meaning."},{"t":"Blessing Tally Chart","d":"Tape a paper to the fridge and add one tally mark every time someone says thank you today. Count the marks at bedtime. Tracking something across a whole day stretches focus and follow-through."}]},{"day":"Wednesday","focus":"Happy H Sounds","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Hop for H","d":"Say a word — if it starts with the /h/ sound like happy, home, or hug, your child hops; if not, they freeze. Sound games train the ear for reading, and the wiggles help it stick."},{"t":"Writing H Together","d":"Show your child that H is two tall lines with a bridge. Practice giant H's in the air, then smaller ones on paper, then spot H on cereal boxes. Big-to-small practice is how handwriting really develops."}]},{"day":"Thursday","focus":"Five Senses Thanks","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Senses Gratitude Walk","d":"Step outside and find one thing you're thankful to see, hear, smell, and touch. Talk about which sense found each one. Sorting the world by senses is real science thinking — with a grateful twist."},{"t":"Mystery Thankful Box","d":"Hide a familiar object in a box and let your child reach in, feel it, and guess what it is. Then share why you're thankful for it. Guessing from clues builds the observing-and-predicting habit scientists use."}]},{"day":"Friday","focus":"Thankful Tree","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Handprint Leaf Tree","d":"Trace your child's hand on yellow paper, cut out leaves together, and write one thankful thing on each — helpers count too, like firefighters and teachers. Tape them to a paper trunk and watch the tree fill up all month."},{"t":"Thank a Helper","d":"Talk about people who help your family — the mail carrier, the doctor, the crossing guard — and draw a picture for one of them. Noticing community helpers is how little citizens start to understand their world."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in the backpack — little thank-yous add up to big hearts.","items":["A “what I'm thankful for” drawing page — one picture a day.","Say the /h/ sound together: happy, home, hug.","Count four blessings on four fingers at bedtime.","Read together tonight — this month's Bear Phonics reader, He Eats Meat, is a lovely place to start."]}},{"label":"Week 2 — Family & Home","days":[{"day":"Monday","focus":"My Family Counts","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Family Number Line","d":"Count everyone in your family — the people at home, plus grandmas and cousins if your child wants. Draw a circle for each and count again. Comparing “more than four, fewer than four” builds real number sense."},{"t":"Every Family Counts","d":"Look at photos and talk about families you know — big ones, small ones, near and far. Every family looks different, and naming that out loud helps your child feel proud of their own."}]},{"day":"Tuesday","focus":"Draw and Tell","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Family Portrait Artist","d":"Ask your child to draw everyone in the family, then label each person together — and have them write their own name at the top. Name writing is a top kindergarten-readiness skill, and portraits make it fun."},{"t":"Family Story Retell","d":"Share a short story about when your child was a baby, then ask them to tell it back to you. Retelling in order — first, next, last — is a big pre-reading muscle."}]},{"day":"Wednesday","focus":"Chore Champions","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Laundry Team-Up","d":"Let your child match socks, carry a small basket, and deliver folded towels to the right rooms. Real jobs build strong bodies and the I-can-finish-a-task pride that fours are hungry for."},{"t":"Chore Charades","d":"Act out a household chore — sweeping, washing dishes, making a bed — and let your child guess, then swap. Guessing games sharpen attention, and you may discover a new little helper."}]},{"day":"Thursday","focus":"Homes Keep Us Safe","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Blanket Fort Home","d":"Build a blanket fort and ask, “What does a home need — a roof? A door? A cozy spot?” Talking about what homes actually do turns snuggling into science."},{"t":"Warm and Safe Chat","d":"At bedtime, name three ways your home keeps you safe and warm — the walls, the blankets, the people inside. Feeling secure at home is the base all other learning stands on."}]},{"day":"Friday","focus":"Love and Rectangles","domains":["Language & Literacy","Mathematical Thinking"],"opts":[{"t":"L Is for Love","d":"L makes the first sound in love and live. Trace a big L on your child's back and let them guess it, then write L's on paper — two straight lines, an easy win. Pair each L with someone they love."},{"t":"Rectangle Room Count","d":"Rectangles are everywhere a family lives — doors, windows, beds, rugs. Walk room to room counting the rectangles you find, and keep a tally. Spotting this month's shape in real life is math off the page."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Home is the first classroom — these keep the learning cozy.","items":["A draw-your-family page for the fridge gallery.","Practice writing L — two straight lines — and your child's own name.","Count the rectangles on one wall together: doors, windows, frames.","Read a bedtime book in the blanket fort — Mrs. Bear's Your Feelings Matter is a cozy pick."]}},{"label":"Week 3 — Sharing & Giving","days":[{"day":"Monday","focus":"Magic Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Restaurant Manners Game","d":"Play restaurant — your child is the server, you're the customer, and every order needs a please and a thank you. Then trade jobs. Practicing manners inside pretend play makes them automatic in real life."},{"t":"K Is for Kind","d":"Tell your child that K starts the word kind — say “k-k-kind” together and brainstorm kind things to do today. Karate-chop the air in a K shape for fun. Attaching a letter to an action makes both stick."}]},{"day":"Tuesday","focus":"Fair Share Math","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Snack Split","d":"Give your child eight crackers and two plates: “Can you make the plates fair?” Then try an odd number and talk about the leftover. Sharing equally is early division — snack included."},{"t":"Deal It Out","d":"Deal out socks, blocks, or crayons saying “one for you, one for me,” then count each pile to check they match. Turn-taking with counting builds fairness and number sense at the same time."}]},{"day":"Wednesday","focus":"Givers Around Us","domains":["Social Studies","Scientific Inquiry"],"opts":[{"t":"Smile Experiment","d":"Run a real investigation: smile at each family member and watch what happens. Do smiles spread? Count how many come back. Fours love an experiment — and this one shows that giving comes back around."},{"t":"Helpers Who Give","d":"Talk about people who give in your community — food-pantry helpers, coat drives, neighbors sharing garden tomatoes. Pick one small way your family could give this month. Big citizenship starts small."}]},{"day":"Thursday","focus":"Pass It Along","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Pass-the-Pillow Relay","d":"Line up the family and pass a pillow down the line — over heads, under legs, behind backs. Everybody helps, nobody rushes. Cooperative games teach fours the teamwork kindergarten expects."},{"t":"Taking Turns Timer","d":"Pick one favorite toy and take turns with a kitchen timer — two minutes each. Cheer your child when the handoff goes smoothly. Waiting for a turn is self-control practice, and self-control predicts school success."}]},{"day":"Friday","focus":"Thank-You Makers","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Thank-You Card Studio","d":"Help your child make a card for someone who helped them this week. They draw, you write down their words, and they sign their own name. Watching writing carry a real message is how literacy clicks."},{"t":"Grateful Story Time","d":"Snuggle up with a story about giving, then read this month's Bear Phonics book, He Eats Meat, and let your child read the words they know. Cheer every sound — readers grow on encouragement."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Sharing week — a few nudges to keep kindness rolling at home.","items":["A thank-you-card kit: folded paper, crayons, one stamp.","Practice the /k/ sound: kind, kite, kangaroo.","Split tonight's snack into two fair shares together.","Catch your child sharing and name it: “That was generous.”"]}},{"label":"Week 4 — A Thankful Feast","days":[{"day":"Monday","focus":"Set the Table","domains":["Physical Development","Mathematical Thinking"],"opts":[{"t":"Table-Setting Captain","d":"Make your child tonight's table captain: count out four plates, four forks, and four cups, and carry them carefully one trip at a time. One-to-one counting plus careful hands — dinner prep is a whole lesson."},{"t":"Napkin Fold and Match","d":"Show your child how to fold napkins into rectangles and place one at each seat. Count as you go and check: does everyone have exactly one? Matching one napkin to one person is real math thinking."}]},{"day":"Tuesday","focus":"Harvest Words","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"H Is for Harvest","d":"Name feast foods together and listen for this month's letters — ham and honey for H, kale for K, lemons and lettuce for L. Sorting foods by their first sound is phonics you can taste."},{"t":"Where Food Comes From","d":"Pick one food from your kitchen and trace its story — a carrot grew in dirt, got picked, rode a truck, and reached your store. Fours love the why behind everyday things, and this builds it."}]},{"day":"Wednesday","focus":"Feast Traditions","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Our Family Feast Story","d":"Tell your child about a feast from your own childhood — who came, what you ate, what made it special. Then ask what they would put in a family feast. Traditions are how children learn who they are."},{"t":"Gratitude Circle","d":"Before one meal this week, hold hands and let each person say one thing they're thankful for. Keep it short and sweet. A tiny ritual like this steadies big feelings and builds belonging."}]},{"day":"Thursday","focus":"Kitchen Helpers","domains":["Approaches to Learning","Mathematical Thinking"],"opts":[{"t":"Little Recipe Helper","d":"Let your child wash, tear, stir, or measure for one dish — counting the scoops out loud together. Following recipe steps in order is planning practice, and kitchen jobs make fours feel mighty."},{"t":"Yellow Food Count","d":"Yellow is this month's color — count the yellow foods in your kitchen: bananas, corn, lemons, butter. Which shelf has the most? Sorting and comparing amounts is math without a worksheet."}]},{"day":"Friday","focus":"Feast and Celebrate","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Paper-Plate Feast Craft","d":"Give your child a paper plate and let them draw their dream feast on it, then present it like a chef: “First we eat…” Describing their work in order builds storytelling."},{"t":"Retell Your Month","d":"Look back together: “What were your favorite thankful things this month?” Let your child retell them while you write their words down and read them back. Seeing their own words in print is powerful."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Feast week — set the table with gratitude and a little math.","items":["Let your child count out plates and cups for dinner all week.","H, K, and L tracing plus a big number 4 to decorate.","A “my dream feast” paper-plate drawing page.","Read He Eats Meat once more and celebrate every word they read alone."]}}]},"dec":{"theme":"Lights & Traditions Around the World","weeks":[{"label":"Week 1 — Lights Around the World","days":[{"day":"Monday","focus":"What Glows?","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Glow Hunt at Dusk","d":"When it gets dark, walk the house together finding things that glow — nightlights, the microwave clock, porch lights. Collect glow words as you go: shine, twinkle, bright. New words stick best when they're attached to real discoveries."},{"t":"Flashlight Test Lab","d":"Turn the lights off and let your child test a flashlight: what does it shine through? A cup? A blanket? Their hand? Predict first, then test — that's the whole scientific method, in the dark."}]},{"day":"Tuesday","focus":"Five Lights Pattern","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Count to Five Lights","d":"Draw five candles or lamps and count them — five is this month's number. Then color them in a repeating pattern: yellow, green, yellow, green. Making patterns is pre-math that kindergarten teachers watch for."},{"t":"Window Light Tally","d":"Tonight, peek out the window and tally the lights you can see — porch lights, lit windows, stars. Which side of the house wins? Comparing counts turns an ordinary window into a math lesson."}]},{"day":"Wednesday","focus":"Twinkle Freeze Dance","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Freeze-Dance Glow","d":"Play music and dance with the lights turned low; when the music stops, freeze like a statue and hold it. Stopping a moving body on cue is real self-regulation — the skill kindergarten asks for most."},{"t":"Cozy Light Calm-Down","d":"Dim the lights, breathe slowly together, and talk about how warm light makes us feel — safe, calm, cozy. Naming calm feelings when things are peaceful helps your child find them when things aren't."}]},{"day":"Thursday","focus":"Celebrations of Light","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Paper Star Lantern","d":"Cut a big star — this month's shape — and decorate it with foil bits or yellow and green paper, then hang it in the window. Around the world, families hang lights and stars to celebrate. Yours joins them."},{"t":"World of Lights","d":"Share that children everywhere celebrate with light — candles, lanterns, strings of bulbs, bonfires. Ask which lights your child has seen with their own eyes. Learning that families celebrate differently grows a wide, warm view of the world."}]},{"day":"Friday","focus":"W Words Shine","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"W Is for Warm","d":"This week's letter is W — warm, window, wonder. Show your child that W is two V's holding hands and write some together, big then small. Then whisper w-w-warm by the window."},{"t":"Walk the W","d":"Tape a giant W on the floor and let your child walk it heel-to-toe, then hop it, then tiptoe it. Moving along a letter's path wires its shape into memory better than any worksheet."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Light week — easy sparks for cozy evenings at home.","items":["A star-shaped coloring page — this month's shape.","Trace W and count five candles.","Turn the lights low and read one book by flashlight together.","Collect glow words on the fridge: shine, twinkle, bright, glow."]}},{"label":"Week 2 — Family Traditions","days":[{"day":"Monday","focus":"My Family Does","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"My Family Always","d":"Ask your child to finish “My family always…” — taco night, Sunday calls to Grandma, pancakes on Saturdays. Write their answers down and read them back. Children speak most richly about the things they love."},{"t":"Grandparent Tradition Call","d":"Call a grandparent or auntie and let your child ask, “What did you celebrate when you were little?” Real conversations with elders build language and roots at the same time."}]},{"day":"Tuesday","focus":"Sort the Season","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Holiday Object Sort","d":"Gather seasonal odds and ends — cards, ribbons, ornaments, candles — and sort them by color, then by size, then by shininess. Re-sorting the same pile in new ways is flexible thinking in action."},{"t":"Count Five Traditions","d":"Help your child count five family traditions on five fingers, then draw a star beside the favorite. Tying counting to their very own life makes the number five feel real."}]},{"day":"Wednesday","focus":"Dance It Out","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Family Dance Party","d":"Put on music your family loves — from any culture or generation — and teach your child a move you grew up with. Then learn one they invent. Dancing together passes traditions along, body to body."},{"t":"Scarf Twirl Show","d":"Hand your child a scarf or dish towel and let them twirl, wave, and swirl it to music, then take a bow. Big arm movements build the shoulder strength that steady handwriting sits on."}]},{"day":"Thursday","focus":"Smells Like Home","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Kitchen Smell Test","d":"Let your child close their eyes and sniff three kitchen smells — cinnamon, orange peel, cocoa. Can they guess each one? Smell ties tightly to memory; you're building their someday-nostalgia right now."},{"t":"Proud of My Family","d":"At bedtime, tell your child one thing that makes you proud of your family, and ask for theirs. Belonging to something bigger steadies a four-year-old's heart."}]},{"day":"Friday","focus":"F Is Family","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Fancy F Practice","d":"F is for family, food, and fun. Practice writing F — one tall line, two little shelves — then label a family drawing with F words. Letters learned inside meaningful projects stay learned."},{"t":"Family Tradition Collage","d":"Tear paper scraps and glue a collage of your family's traditions — foods, music, places, colors. Let your child explain each piece while you listen. Explaining a creation is storytelling practice."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tradition week — keep the family stories flowing.","items":["A “my family always…” share card to fill in together.","Practice F: one tall line, two little shelves.","Read together in a brand-new spot tonight — under the table counts.","Sort five seasonal objects by color, then by size."]}},{"label":"Week 3 — Giving & Kindness","days":[{"day":"Monday","focus":"N for Neighbor","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Nice Neighbor Notes","d":"N says n-n-nice. Practice writing N — down, slide, down — then make a tiny note with a smiley face to leave at a neighbor's door. Writing with a real purpose beats a worksheet every time."},{"t":"Neighborhood Kindness Map","d":"Draw your street together and mark the neighbors you know. Who could use a hello or a wave this week? Thinking about the people around us is early citizenship."}]},{"day":"Tuesday","focus":"Gift Math","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Count and Wrap","d":"Choose five little things to give away — drawings, painted rocks, kind notes — and count them into a bag, then recount to check. Counting for a kind reason gives math a heartbeat."},{"t":"How Giving Feels","d":"After your child gives something — a hug, a toy turn, a drawing — ask, “How did that feel in your body?” Warm? Fizzy? Proud? Naming the good feeling after giving teaches them to chase it again."}]},{"day":"Wednesday","focus":"Deliver with Care","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Gift Delivery Relay","d":"Set a delivery route through the house — carry a “gift” (a stuffed animal works) over the pillow mountain, around the table, to the drop-off spot without dropping it. Careful carrying builds coordination and focus."},{"t":"Wrapping Station","d":"Let your child wrap a small box with paper scraps and tape — no perfection allowed. Folding, holding, and taping is a fine-motor workout disguised as fun."}]},{"day":"Thursday","focus":"Warm Heart Test","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Kindness Ripple Test","d":"Run an experiment: do one kind thing for someone, then secretly watch — do they do something kind next? Report your findings at dinner. Fours make wonderful kindness scientists."},{"t":"Warm Hands, Warm Hearts","d":"Rub your hands together fast and feel them heat up, then talk about how giving warms us up on the inside the same way. A little physics, a little feelings — fours love it when ideas connect."}]},{"day":"Friday","focus":"Make and Give","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Homemade Gift Studio","d":"Help your child make one gift — a drawing, a cardboard picture frame, a painted rock — for someone specific, and have them sign their name. Making something for others is creativity with a mission."},{"t":"Giving Story Snuggle","d":"Read a story about giving tonight, then read this month's Bear Phonics book, We See Feet, letting your child sound out the words they know. Cheer the effort, not just the answer."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Kindness week — small hands, generous hearts.","items":["A kindness idea list: wave, share, help carry, say thank you.","Practice N — down, slide, down — on sticky notes.","Count five kind acts on five fingers at bedtime.","Deliver one homemade gift together this weekend."]}},{"label":"Week 4 — Celebrations","days":[{"day":"Monday","focus":"Parade Time","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Kitchen Band Parade","d":"Make shakers from dry rice or beans sealed tight in a container, grab a pot-lid drum, and march a parade through the house — high knees, big steps. Marching to a beat builds rhythm and body control."},{"t":"Streamer March","d":"Tape paper strips to a spoon for a streamer wand and take turns leading the march — wave high, wave low, spin on the spot. Following a leader's moves builds the watch-and-copy skill school relies on."}]},{"day":"Tuesday","focus":"Countdown to Fun","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Countdown Blast Off","d":"Count down from five before anything fun today — five, four, three, two, one, lights on. Counting backward is trickier than counting forward, and it's a real kindergarten skill."},{"t":"Party Table Math","d":"Plan a pretend party: how many cups does our family need? Set them out, count, and check. Now add a teddy bear guest — how many now? That little “one more” question is early addition."}]},{"day":"Wednesday","focus":"Tell the Story","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Retell a Celebration","d":"Ask your child to tell the story of a celebration they remember — a birthday, a parade — with a beginning, middle, and end. Prompt gently: “What happened first?” Retelling in order is a top pre-reading skill."},{"t":"We Celebrate Together","d":"Talk about why people gather to celebrate — to share joy, remember special days, and simply be together. Then ask your child what every celebration needs. There's no wrong answer, and the thinking is the point."}]},{"day":"Thursday","focus":"Sounds of Joy","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Sound Makers Lab","d":"Test which household things make the best celebration sounds — a rubber-band guitar, or spoon-taps on cups filled to different water levels. Predict, test, compare. That's inquiry with a soundtrack."},{"t":"Joy Check-In","d":"Ask, “What does excited feel like in your body?” Jumpy legs? A fast heart? Then practice one slow breath to settle. Naming big feelings — even the happy ones — is self-regulation practice, and Mrs. Bear's Your Feelings Matter is a sweet companion read."}]},{"day":"Friday","focus":"O Finale","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"O All Around","d":"O is a circle — the easiest letter to spot. Find O's on cereal boxes, lids, and wreaths, then write a row of O's and turn each one into something: a face, a sun, an ornament. Playful practice sticks."},{"t":"Celebration Wall","d":"Hang your child's month of makings — stars, collages, notes — into a mini gallery and let them give the family a tour. Presenting their own work builds confident, connected speech."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Celebration week — end the month with joy you can hang on the fridge.","items":["Trace W, F, N, and O — then circle the O's hiding on a cereal box.","A count-down-from-five card for smoother transitions.","Read We See Feet together and let your child be the teacher.","A green star to color and hang in the window."]}}]},"jan":{"theme":"Winter Wonders","weeks":[{"label":"Week 1 — Snow & Ice","days":[{"day":"Monday","focus":"Ice Explorers","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Ice Cube Race","d":"Set out two ice cubes — one in a sunny spot, one in the shade — and predict which melts first. Check back and talk about why. Predict, observe, explain: that's the heart of science, straight from your freezer."},{"t":"Frozen Toy Rescue","d":"Freeze a few small toys in a cup of water overnight, then let your child figure out how to free them — warm water? Spoon taps? Patience? Problem-solving with a mission keeps fours gloriously busy."}]},{"day":"Tuesday","focus":"Six Snowballs","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Paper Snowball Count","d":"Crumple six paper snowballs — six is this month's number — and count them into a basket, then dump and count again. Toss them in from farther and farther back for a throwing challenge."},{"t":"Freeze and Melt","d":"Call out “freeze” and your child holds an icy statue; call “melt” and they slowly puddle down to the floor while you count to six. Controlling a body slowly is harder than moving fast — that's the workout."}]},{"day":"Wednesday","focus":"Cold Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Winter Word Collectors","d":"Collect cold words together — snow, ice, frost, chilly, shiver — and count how many you gather. Say each one in your best shivery voice. A rich word bank now becomes strong reading later."},{"t":"Cozy Corner Feelings","d":"Build a cozy corner with a blanket and pillow, then talk about how warm-and-safe feels after some pretend shivering. Naming calm, cozy feelings gives your child a word for what settles them."}]},{"day":"Thursday","focus":"Snowy Places","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Where Snow Lives","d":"Talk about places where snow falls — mountains, way up north, other countries — and whether it ever snows where you live. Fours love discovering that weather is different around the world."},{"t":"Cotton-Ball Snow Scene","d":"Glue cotton balls onto blue paper to build a snowy place — a snowman, a snowy hill, a snow-covered house. Let your child describe their scene while you write a title for it together."}]},{"day":"Friday","focus":"Diamond Snowflakes","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"D Is for Diamond","d":"This week's letter is D — a tall line, then around. Practice writing D, then draw diamonds, this month's shape, and turn them into sparkly snowflakes. Letter and shape in one sitting, and both start with D."},{"t":"Snowy Story Time","d":"Read a snowy-day story or this month's Bear Phonics book, Feed Me, and ask your child what they would do on a snowy day. Connecting books to their own ideas is comprehension in action."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Snow week — no snow required, the freezer has you covered.","items":["Freeze a small toy in a cup of water for a morning rescue mission.","Trace D and draw six diamonds.","Collect cold words at dinner: frost, icy, shiver.","Read a snowy book together under a blanket."]}},{"label":"Week 2 — Winter Animals","days":[{"day":"Monday","focus":"Animal Moves","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Waddle, Stomp, Pounce","d":"Move like winter animals together — waddle like a penguin, lumber like a bear, pounce like a fox. Then ask, “Why might a penguin waddle?” Moving plus wondering is a four-year-old's favorite kind of science."},{"t":"Animal Guess Show","d":"Act out a winter animal with no words and let the family guess, then swap. Thinking hard about how an animal really moves builds observation skills — and plenty of giggles."}]},{"day":"Tuesday","focus":"Sort the Animals","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Stuffed Animal Sort","d":"Gather the stuffed animals and sort them: fur or feathers? Big or small? Sleeps all winter or stays awake? Count each group and compare. Sorting by a rule is real math brainpower."},{"t":"Animal Line-Up","d":"Line up six animal toys from smallest to biggest, then count them forward and backward. Ordering by size looks simple, but it is real math thinking — and fours can absolutely do it."}]},{"day":"Wednesday","focus":"P Is Penguin","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"P Words on Parade","d":"P says p-p-penguin. Practice writing P — a tall line with a round bump at the top — then collect P words: polar bear, paw, pounce. Say them in a puffed-up penguin voice for fun."},{"t":"Handprint Penguin","d":"Paint or trace your child's hand, turn it upside down, and transform it into a penguin — add eyes, a beak, and snowy dots. Then have them write a P beside it. Art plus letters is double learning."}]},{"day":"Thursday","focus":"Sleep or Go?","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Hibernate or Migrate","d":"Teach two grown-up words: hibernate (sleep the winter away, like bears) and migrate (travel somewhere warm, like some birds). Sort animals into the two groups. Fours adore big words — hand them over."},{"t":"Den Builders","d":"Build a bear den from cushions and let your child hibernate — crawl in, curl up, snore. Then ask what a real bear would need in its den. Pretend play is how fours digest new ideas."}]},{"day":"Friday","focus":"Gentle Friends","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Bird Watch Helpers","d":"Talk about how people help animals in winter — filling bird feeders, bringing pets inside. Then set out a dish of water or sprinkle birdseed where you can watch from a window. Caring for living things grows empathy."},{"t":"Gentle Hands Practice","d":"Practice gentle with a pet or a stuffed animal — slow strokes, quiet voice. Ask, “How do we know an animal feels safe with us?” Reading an animal's signals is empathy training."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Winter animal week — waddles, dens, and gentle hands.","items":["Practice P: a tall line with a round bump.","A hibernate-or-migrate sorting game with stuffed animals.","Watch for birds out the window and count the ones you spot.","Read an animal story and ask, “What would you do all winter?”"]}},{"label":"Week 3 — Staying Warm & Cozy","days":[{"day":"Monday","focus":"Bundle-Up Relay","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Bundle-Up Race","d":"Pile up a jacket, hat, and mittens (socks on hands work fine) and time your child bundling up, then let them time you. Zippers and buttons are fine-motor gold, and beating their own time builds stick-with-it spirit."},{"t":"Sock Skating Rink","d":"Clear a smooth stretch of floor and let your child skate in socks — long glides, careful turns, a big finish pose. Balance and control, no ice required."}]},{"day":"Tuesday","focus":"Mitten Math","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Mitten Pair Match","d":"Scatter gloves, mittens, and socks and let your child find the pairs, counting by twos as they match: two, four, six. Pairs are an early doorway into skip counting."},{"t":"Winter Clothes Words","d":"Name winter clothes together — hat, scarf, boots, mittens — and clap the syllables in each one: mit-tens, two claps. Syllable clapping is a reading-readiness classic you can play anywhere."}]},{"day":"Wednesday","focus":"Cozy Quilt Lab","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Warm Jar Test","d":"Fill two jars with warm tap water; tuck one inside a sock and leave one bare. Feel them later — which stayed warmer? That's exactly what coats do: keep our own warmth in. A cozy experiment your child will retell for days."},{"t":"Quilt Fort Quiet","d":"Q is for quilt and quiet. Build a quilt fort and practice the quiet part — two minutes of whisper-talk or slow breathing inside. A calm-down spot they built themselves actually gets used."}]},{"day":"Thursday","focus":"Winter Helpers","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Who Helps in Winter","d":"Talk about people who help when it's cold — power-line crews, coat-drive volunteers, neighbors checking on grandparents. Then ask, “Who could we help stay warm?” Fours are ready for real citizenship."},{"t":"Warm Wishes Note","d":"Let your child tell you a warm wish for someone — you write their words, they decorate the page and sign their name. Sending words to a real person shows a four-year-old that writing has power."}]},{"day":"Friday","focus":"Design a Mitten","domains":["Creative Expression","Mathematical Thinking"],"opts":[{"t":"Mitten Designer Studio","d":"Trace your child's hand into a mitten shape and let them fill it with a repeating pattern — diamond, dot, diamond, dot. Patterns that repeat are math; making them beautiful is art."},{"t":"Blue Cozy Collage","d":"Blue is this month's color — gather blue scraps, blue crayons, and little blue bits, and glue the coziest blue collage: blankets, mittens, winter sky. Talk through their choices as they work."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Cozy week — warmth you can practice at home.","items":["Practice Q: a circle with a little tail.","Match mitten and sock pairs from the laundry, counting by twos.","Build a quilt fort and read one book inside it — Mrs. Bear's Your Feelings Matter is a snug fit.","A design-your-own-mitten page with a diamond pattern."]}},{"label":"Week 4 — Winter Fun","days":[{"day":"Monday","focus":"Snowball Games","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Sock Snowball Toss","d":"Roll socks into snowballs and take turns tossing them into a laundry basket — step back a step after every hit. Taking turns and cheering for each other is the real game under the game."},{"t":"Blanket Bounce","d":"Lay sock snowballs on a blanket, each grab a corner, and bounce them like popcorn without letting any fall. Teamwork toward a shared goal is pure pre-K social learning."}]},{"day":"Tuesday","focus":"Winter Fun Graph","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Family Favorites Graph","d":"Ask everyone their favorite winter fun — cocoa night, movie night, blanket forts — and graph the votes with blocks or tally marks. Which one won? Reading a graph they built themselves is real data thinking."},{"t":"Six-Game Challenge","d":"Make a checklist of six mini-games — hop six times, do six jumping jacks, toss six snowballs — and check each one off. Following a plan all the way to the end is the focus muscle school needs."}]},{"day":"Wednesday","focus":"See Your Breath","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Foggy Mirror Magic","d":"Breathe on a mirror or a cold glass and watch it fog up, then draw a quick picture in the fog before it fades. Ask why it happens — warm breath meeting something cool. Wondering out loud is the lesson."},{"t":"Why Jar Wonders","d":"Keep a “why jar” this week — every winter why goes in on a slip: Why is ice slippery? Why do we shiver? Pull one out at dinner and wonder together. The questions matter more than perfect answers."}]},{"day":"Thursday","focus":"Winter Fun Worldwide","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Winter Games Worldwide","d":"Share how children play in winter around the world — sledding, ice skating, snow sculptures, festivals with lights and kites. Ask which one your child would try first. The world gets bigger one wondering at a time."},{"t":"Snowflake Paint Prints","d":"Dip a fork or a cut cardboard-tube stamp in white or blue paint and print snowflakes across dark paper. Every real snowflake is different — let theirs be too."}]},{"day":"Friday","focus":"Letter Review Day","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Letter Hopscotch","d":"Write D, P, and Q on paper squares, tape them to the floor, and call out letters — or just their sounds — for your child to hop to. Reviewing the month's letters with a moving body makes them stick."},{"t":"Winter Reading Picnic","d":"Spread a blanket, pour something warm, and read Feed Me together — let your child read every word they can, then retell their favorite winter memory from the month. Ending a month with books is always right."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Winter fun week — wrap up the month with games and giggles.","items":["Trace D, P, and Q, then decorate a big number 6.","A sock-snowball game card: toss, count, cheer.","Breathe on a cold glass and draw in the fog.","Read Feed Me and celebrate the words they read all by themselves."]}}]},"feb":{"theme":"Kindness & Friendship","weeks":[{"label":"Week 1 — What Is a Friend?","days":[{"day":"Monday","focus":"What Makes a Friend","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Friend Talk Time","d":"At snack or dinner, ask your child, “What makes someone a good friend?” Write their answer on paper while they watch. Seeing their own words turn into print is powerful pre-reading practice."},{"t":"Friendship Story Retell","d":"Read a favorite book about friends together, then invite your child to retell it to a stuffed animal — beginning, middle, and end. Retelling builds the comprehension kindergarten teachers look for."}]},{"day":"Tuesday","focus":"Mirror a Friend","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Mirror Moves","d":"Stand face-to-face and take turns being the leader — slow arm circles, silly faces, tiptoe stretches — while the other copies like a mirror. Copying a partner builds body control and real attention to another person."},{"t":"Follow the Leader Walk","d":"Take a walk where the leader changes at every mailbox — march, hop, giant steps. Following a friend’s moves is cooperation in disguise."}]},{"day":"Wednesday","focus":"Counting Our Friends","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"My Love Circle","d":"Draw the people who care about your child — family, neighbors, school friends — then count the faces, touching each one as you say the number. Fours are ready to count well past ten, so keep the crowd growing."},{"t":"Lucky Number 7","d":"Set out 7 spoons, 7 socks, and 7 crackers and count each group. Then ask, “Are they the same amount even though they look different?” That is a big pre-K math idea."}]},{"day":"Thursday","focus":"Alike & Different","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Same and Different Study","d":"Look closely at two family members’ hands — size, lines, freckles. Talk about what is alike and what is different, just like friends are. Careful observation is the heart of science."},{"t":"Sock Pair Detectives","d":"Dump the clean sock basket and hunt for pairs, describing what matches and what does not. Sticking with a sorting job all the way to the end builds focus for school."}]},{"day":"Friday","focus":"Friendship Portraits","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Draw a Friend","d":"Have your child draw a portrait of a friend, then help them label it with the friend’s name and sign their own. Name writing is one of the biggest kindergarten-readiness wins there is."},{"t":"R Is for Respect","d":"Practice the rrr sound, write a big R and a little r, and think of friendly R words together — respect, ready, rainbow. Knowing letter sounds now makes reading easier later."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in the backpack — little friendship builders for home.","items":["Ask “Who did you play with today?” at pickup and really listen.","Trace R and r on the practice page, then spot R words around the house.","Count 7 of anything — steps, crackers, hugs.","Read one friendship story together before bed and name how each character feels."]}},{"label":"Week 2 — Kind Words & Deeds","days":[{"day":"Monday","focus":"Kind Words Practice","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Kind Words Jar","d":"Write kind phrases together — “thank you,” “good job,” “want to play?” — on paper slips for a jar. Pull one each morning and use it before dinner. Kind language sticks when it is practiced out loud."},{"t":"Umbrella of Kindness","d":"Draw a big umbrella and practice the letter U while you fill it with kind words your child dictates. Hearing the short-u sound in umbrella and up ties phonics right to the theme."}]},{"day":"Tuesday","focus":"Kindness Delivery","domains":["Physical Development","Social Studies"],"opts":[{"t":"Kindness Relay","d":"Set up a delivery relay — race to bring a cup of water to Grandma, a towel to the laundry, a hug to a sibling. Big-muscle work plus helping equals a very happy four-year-old."},{"t":"Wave and Greet Walk","d":"Walk your street and practice friendly greetings — a wave, “good morning,” holding a door. Neighborhoods feel kinder when kids learn they belong to one."}]},{"day":"Wednesday","focus":"Counting Kind Acts","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Kindness Count Jar","d":"Drop a piece of dried pasta in a jar for every kind act you both spot today, then count the jar at bedtime. Watching a total grow makes adding feel real."},{"t":"Heart Patterns","d":"Cut simple paper hearts in pink and red and build a repeating pattern — pink, red, pink, red. Then let your child make a trickier one for you to continue. Patterns are pre-K math gold."}]},{"day":"Thursday","focus":"How Kindness Feels","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Body Clues Check","d":"After a kind moment, play scientist — “What do you notice in your body? Warm cheeks? A smiley feeling in your chest?” Noticing body clues builds self-awareness and observation skills at once."},{"t":"Feelings Check-In","d":"Read Your Feelings Matter together, or any feelings book you love, then try a morning check-in — “How does your heart feel today?” Naming feelings is the first step to managing them."}]},{"day":"Friday","focus":"Bucket Filling","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Fill-a-Bucket Cup","d":"Decorate a paper cup as a family bucket and drop in notes about kind deeds you catch each other doing. Read them aloud on Sunday — dictated notes count as writing practice too."},{"t":"Kindness Coupons","d":"Make kindness coupons — “one hug,” “I will set the table” — that your child decorates and gives to family. Dictating the words and signing their name is real writing with a real purpose."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week we are filling buckets — here is how to keep it going at home.","items":["Catch your child being kind and name it out loud — “That was respectful.”","Trace U and u, then listen for the uh sound in up, under, and umbrella.","Keep a family kindness jar and count it together on Sunday.","Do one secret kind deed together and keep it a happy secret."]}},{"label":"Week 3 — Working Together","days":[{"day":"Monday","focus":"Team Building","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Tower Team-Up","d":"Build one tall tower together, strictly taking turns — one block for you, one for them — and count every block as it stacks. Turn-taking plus counting to 20 is a whole pre-K lesson in one game."},{"t":"Cup Stack Challenge","d":"Stack a pyramid of paper or plastic cups as a team, then count how many you used. When it tumbles, cheer and rebuild — bouncing back together is the real skill."}]},{"day":"Tuesday","focus":"Cooperative Moves","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Back-to-Back Stand","d":"Sit on the floor back-to-back, link elbows, and try to stand up together without using hands. It only works when both partners push at the same moment — teamwork you can actually feel."},{"t":"Big Pillow Carry","d":"Carry the biggest pillow in the house across the room together — no dropping. Then try a loaded laundry basket. Jobs that truly need two people teach cooperation better than any lecture."}]},{"day":"Wednesday","focus":"Team Words","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"V for Victory","d":"Make a V with your arms every time your team finishes a job today, and practice the vvv sound — victory, van, vegetables. Attach a cheer to a letter and it sticks."},{"t":"Read Together Time","d":"Read a story about characters who work together, then ask, “Who helped, and how?” If your child is doing Bear Phonics, let them read The Deer Sees Seeds to you — readers love an audience."}]},{"day":"Thursday","focus":"Two Hands Help","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"One Hand or Two","d":"Try zipping a jacket, pouring water, and folding a towel with one hand, then with two. Predict first, test, and talk about what happened — that is a real experiment."},{"t":"Sock Toss Tally","d":"Toss sock balls into a laundry basket as a team and tally the makes on paper, counting the marks at the end. Predict how many you will sink before you start."}]},{"day":"Friday","focus":"Group Mural","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Family Mural","d":"Tape a big piece of paper or a flattened cardboard box to the floor and let everyone add to one picture. Shared art teaches compromise — whose sky is it? Everyone’s."},{"t":"Team Handprint Heart","d":"Trace everyone’s hands in a heart shape on one page, pink and red crayons welcome. Hang it where the whole family can see what together looks like."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Teamwork week — these little jobs work best with two sets of hands.","items":["Give your child one real two-person job a day, like folding a big blanket.","Trace V and v, then flash an arm-V cheer when jobs get done.","Count the blocks or cups in your tallest team tower.","Read together every night — take turns picking the book."]}},{"label":"Week 4 — Hearts & Helpers","days":[{"day":"Monday","focus":"Helper of the Day","domains":["Social Studies","Physical Development"],"opts":[{"t":"Real Helper Jobs","d":"Give your child a real helper job with big movements — carrying laundry, watering plants, wiping the table. Four-year-olds stand taller when the job actually matters."},{"t":"Helper Charades","d":"Act out community helpers — firefighter, mail carrier, doctor, teacher — and guess each one. Talk about how each of those people helps your family."}]},{"day":"Tuesday","focus":"Thank-You Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Thank-You Note","d":"Help your child make a thank-you note for a helper they love — they dictate the message, you write it, they sign their name big and proud. Gratitude plus name writing in one sitting."},{"t":"Gratitude Go-Round","d":"At dinner, everyone names one person who helped them today and what they did. Hearing grown-ups practice gratitude teaches more than any reminder ever could."}]},{"day":"Wednesday","focus":"Heart Math","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Heart Sort and Count","d":"Cut paper hearts in a few sizes and colors, then sort them — big or small, pink or red — and count each pile. Ask which pile has more; comparing groups is true pre-K math."},{"t":"Seven-Heart Line","d":"Make a line of 7 hearts, number them 1 to 7, and secretly remove one — which number is missing? Missing-number games sharpen counting more than reciting ever will."}]},{"day":"Thursday","focus":"My Beating Heart","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Heartbeat Jump Test","d":"Feel your heartbeats with a hand on the chest, then jump 10 times and feel again. What changed? Predict, test, and talk — a true four-year-old science lab."},{"t":"Paper-Tube Stethoscope","d":"Listen to a family member’s heart through a cardboard tube like a doctor. Take a guess first about whether a grown-up’s heart sounds different — curiosity is the engine of learning."}]},{"day":"Friday","focus":"Valentines for Friends","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Homemade Valentines","d":"Make simple valentines for friends and family — paper hearts, doilies if you have them, plenty of crayon love. Your child writes their own name on each one; that signature is kindergarten gold."},{"t":"R, U, V Review","d":"Write R, U, and V on paper hearts, spread them out, and call a sound for your child to grab. Then read one more friendship story together to close out the month."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Hearts and helpers — send the love home with these.","items":["Let your child be Helper of the Day with one real job they own.","Trace R, U, and V one more time, then celebrate with a V-for-victory cheer.","Count and sort 7 paper hearts by size or color.","Deliver a homemade valentine or kindness coupon to someone who helps your family."]}}]},"mar":{"theme":"Things That Grow","weeks":[{"label":"Week 1 — Seeds & Plants","days":[{"day":"Monday","focus":"Seed Detectives","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Kitchen Seed Search","d":"Slice an apple, a pepper, or a tomato and go looking for the seeds inside. Compare — which fruit hides the most? Which seeds are biggest? Real produce beats any worksheet."},{"t":"Bean in a Bag","d":"Tuck a dried bean into a damp paper towel inside a zip bag and tape it to a sunny window. Ask your child to predict what will happen, then check it every day. The waiting is part of the lesson."}]},{"day":"Tuesday","focus":"Grow Big Moves","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Seed to Tree Stretch","d":"Curl up tiny like a seed, then slowly sprout — roots, stem, leaves, branches waving in the wind. Do it in slow motion, then double speed. Big-body storytelling builds control."},{"t":"Oval Body Shapes","d":"Challenge your child to make an oval with their arms, with their whole body, and with a belt or string on the floor. March’s shape is more fun when you can climb inside it."}]},{"day":"Wednesday","focus":"Seed Math","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Count to Eight","d":"Count out groups of 8 seeds, dried beans, or pasta pieces, then split one group in half and ask, “How many in each pile?” Little splitting games plant early addition."},{"t":"Plant Part Labels","d":"Draw a flower together and label seed, root, stem, and leaf — you write, your child copies the first letter of each word. Science words are reading words too."}]},{"day":"Thursday","focus":"Farmers Feed Us","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Follow the Food","d":"At the store or the table, trace one food backwards — bread came from wheat, and a farmer grew the wheat. Thank a farmer out loud. Kids love knowing the world is full of helpers."},{"t":"Patience Practice","d":"Check on your bean bag or a houseplant together and talk about patience — good things take time. Ask what else takes time: a birthday, a puzzle, learning to read."}]},{"day":"Friday","focus":"I Sounds & Sprouts","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Long I Day","d":"Practice the long-i sound — I, ride, slide, vine — and write a capital I and a little i. If your child is doing Bear Phonics, read one of the long-i little readers together and let them shine."},{"t":"Sprout Journal","d":"Start a simple grow journal — your child draws what the bean or a plant looks like today and dates the page with your help. Watching change over time is the scientist’s habit."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Seed week — a few tiny things to grow at home.","items":["Plant one seed in a cup and put your child in charge of watering it.","Trace I and i, then listen for the long i in ride, slide, and shine.","Count 8 seeds or beans at snack time.","Read a growing story together and ask what the plant needed."]}},{"label":"Week 2 — In the Garden","days":[{"day":"Monday","focus":"Pretend Garden","domains":["Physical Development","Social Studies"],"opts":[{"t":"Dig, Rake, Water","d":"Set up a pretend garden — dig with a big spoon, rake with fingers, water with a cup — inside or out. Add real weeding if you have a yard. Gardens grow gross-motor skills too."},{"t":"Community Garden Talk","d":"On a walk or a drive, spot gardens, planters, and window boxes and talk about who takes care of each one. Neighbors growing food and flowers is community in action."}]},{"day":"Tuesday","focus":"Measure the Garden","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"How Tall Today","d":"Measure a houseplant or your window bean with blocks, spoons, or paper clips — “It is four blocks tall.” Measure again in a few days and compare. That is data, four-year-old style."},{"t":"Plant Part Check","d":"Examine a real plant up close — find the stem, the leaves, and where the roots hide. Ask, “What job does each part do?” Why-questions are exactly right for this age."}]},{"day":"Wednesday","focus":"Garden Words & Art","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Label the Garden","d":"Draw a garden picture together and label the parts — your child tells you the words, you write them, they copy a letter or two. Purple flowers strongly encouraged this month."},{"t":"Paper Flower Craft","d":"Make flowers with oval petals from scrap paper and count the petals as you glue. A crayon vase and their name signed at the bottom finishes the masterpiece."}]},{"day":"Thursday","focus":"Care for a Plant","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Plant Keeper Job","d":"Put your child fully in charge of one plant this week — checking the soil, watering gently, reporting the news. Real responsibility grows confidence you can see."},{"t":"Slow and Steady Chart","d":"Make a simple chart with a box for each day your child cares for the plant, and check it off together. Sticking with one job all week is kindergarten-level persistence."}]},{"day":"Friday","focus":"Letter X Fun","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"X Marks the Spot","d":"Make an X with sticks, spoons, or your whole bodies, then hide a small treasure and mark the spot with a tape X. X is a rare letter, so make it a memorable one."},{"t":"Blanket Fort Reading","d":"Build a blanket greenhouse and read a garden story inside with a flashlight. Cozy reading spots turn books into treats your child asks for again."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Garden week — grow a little green thumb at home.","items":["Let your child water one plant every day this week.","Measure your plant with blocks or spoons and write the number down.","Trace X and x, then cross your arms in a big X cheer.","Read a garden story together in a cozy blanket fort."]}},{"label":"Week 3 — Baby Animals","days":[{"day":"Monday","focus":"Move Like Babies","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Baby Animal Moves","d":"Waddle like a duckling, hop like a bunny, curl like a kitten, wobble like a brand-new foal. Call out grown-up animals and let your child become the baby version."},{"t":"Animal Sound Parade","d":"March around the house as a baby-animal parade, taking turns adding sounds — peep, mew, yip. Silly, active, and secretly great listening practice."}]},{"day":"Tuesday","focus":"Animal Baby Names","domains":["Language & Literacy","Mathematical Thinking"],"opts":[{"t":"Name the Baby","d":"Play the matching word game — dog and puppy, cat and kitten, cow and calf, hen and chick. Vocabulary like this shows up on kindergarten readiness checklists."},{"t":"Count the Chicks","d":"Draw a hen with 8 chicks and count them together, then cover a few with your hand — “How many are hiding?” Hiding games quietly build early subtraction."}]},{"day":"Wednesday","focus":"Life Cycle Order","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Egg, Baby, Grown","d":"Draw three quick cards — egg, chick, hen — mix them up, and have your child put them in order while telling the story. Sequencing is science and storytelling at once."},{"t":"Wonder Questions","d":"Ask one big wonder question at lunch: “Do all animals start as eggs? Do puppies?” Guess together, then look it up tonight. Modeling curiosity is the whole game."}]},{"day":"Thursday","focus":"Gentle & Caring","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Soft as a Lamb","d":"Pretend a stuffed animal is a brand-new baby lamb and give it your gentlest care — soft pats, a quiet voice, careful carrying. Talk about how babies and pets need our gentlest selves."},{"t":"Who Cares for Animals","d":"Talk about the people who care for animals — vets, farmers, shelter helpers, zookeepers. Ask, “What would you feed a baby goat?” and enjoy the answer."}]},{"day":"Friday","focus":"Z Is for Zoo","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Zippy Z Day","d":"Practice the zzz sound — zoo, zebra, zigzag, zip — and write Z with big zigzag arm strokes before trying it on paper. Letters stick when the body learns them too."},{"t":"Adopt-a-Baby Drawing","d":"Read a baby-animal story together, then have your child draw the baby animal they would adopt and tell you three things it needs. Retelling plus drawing equals comprehension."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Baby animal week — gentle hands and growing hearts.","items":["Play name-the-baby at dinner: cow and calf, sheep and lamb.","Trace Z and z with a zigzag finger in the air first.","Count 8 baby animals in a drawing, then hide a few and count again.","Read an animal story and practice your gentlest stuffed-animal care."]}},{"label":"Week 4 — Growing Me","days":[{"day":"Monday","focus":"How Tall Am I","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Doorway Measure-Up","d":"Mark your child’s height with tape on a doorway and measure it in blocks or hand-widths, counting together. Ask, “How much have you grown since you were a baby?”"},{"t":"Family Height Line-Up","d":"Line the family up shortest to tallest, then compare — who is taller, who is shorter, who is in between? Ordering by size is real pre-K math."}]},{"day":"Tuesday","focus":"Baby Me, Big Me","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Baby Photo Stories","d":"Look at your child’s baby photos and tell the stories — first steps, first words. Then finish sentences together: “When I was a baby I… but now I can…” Past-and-present talk stretches language."},{"t":"Big Kid Award List","d":"Make a proud list of things your child can do now that they could not do at two — you write, they sign their name at the bottom. Read the list aloud like an award."}]},{"day":"Wednesday","focus":"Growing Skills Course","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Big Kid Obstacle Course","d":"Build a quick course of big-kid skills — hop on one foot, zip a jacket, button a shirt, balance-walk a tape line. Cheer for the tricky ones; wobbling is learning."},{"t":"Try Something Tricky","d":"Pick one skill just out of reach — tying a knot, pouring from the big jug — and practice it together for five minutes. Say “You have not got it yet.” Yet is a powerful word."}]},{"day":"Thursday","focus":"My Growing Story","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Then-and-Now Portrait","d":"Fold a paper in half and draw baby-me on one side and big-me-now on the other. Talk through the differences while they draw — more hair, bigger shoes, brand-new skills."},{"t":"Family Growing Tales","d":"Ask a grandparent or relative, in person or on a call, to tell about when your child’s parent was little. Family stories teach children they belong to something bigger."}]},{"day":"Friday","focus":"Number 8 Review","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Great Eight Day","d":"Trace the number 8 — two stacked circles — then count out 8 of something around the house and count it twice to be sure. Add 8 jumps so the body gets a vote."},{"t":"Letter Review Read","d":"Review the I, X, and Z sounds, then read this month’s Bear Phonics long-i reader one more time. Fluent second readings build confident readers."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Growing-me week — celebrate how far your little one has come.","items":["Mark height on the doorway and date it — check again this summer.","Finish the sentence together: “Now that I am big, I can…”","Trace the number 8 and count 8 hops, 8 claps, 8 kisses.","Read baby photos like a storybook — then read a real book together."]}}]},"apr":{"theme":"Our Big Blue Earth","weeks":[{"label":"Week 1 — Land & Water","days":[{"day":"Monday","focus":"Our Home Planet","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Meet Planet Earth","d":"Look at a globe, a map, or a drawn circle of blue and green and introduce the big idea: we all live on planet Earth. Ask, “Is there more land or more water?” and take guesses."},{"t":"Earth Words","d":"Start a list of Earth words — land, water, ocean, mountain, island — and let your child illustrate one. New words plus drawing is vocabulary that sticks."}]},{"day":"Tuesday","focus":"Land & Water Moves","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Cross the Ocean","d":"Lay out a blue blanket ocean with pillow islands and travel across — swim the water, hop the land. Then change one rule and watch your child adapt on the fly."},{"t":"Animal Move Guessing","d":"Move like a land or water animal — gallop, slither, paddle — and have your family guess the animal and where it lives. Then swap so your child does the guessing."}]},{"day":"Wednesday","focus":"Sort & Count Animals","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Land or Water Sort","d":"Gather toy animals, or draw quick cards, and sort them — land or water? Count each group and compare which has more. Some animals fit both; let the happy debate happen."},{"t":"Nine Fish Count","d":"Draw a bowl with 9 fish and count them, then ask, “If one swims behind the plant, how many can we see?” Playful hiding builds early subtraction."}]},{"day":"Thursday","focus":"Water Wonder","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Waves in a Bottle","d":"Fill a clear bottle most of the way with water, add one drop of blue food coloring, and screw the lid on tight. Rock it slowly and watch the waves roll — your child is holding a tiny ocean. Ask what makes real waves move."},{"t":"Favorite Nature Talk","d":"Share your favorite outdoor places with each other — a beach, a backyard, a puddle after rain. Talking about awe teaches kids that nature is worth caring for."}]},{"day":"Friday","focus":"Blue-Green Earth Art","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"My Earth Craft","d":"Make an Earth — a paper plate or circle colored blue and green, teal swirls welcome. Hang it up and help your child label it “our home.”"},{"t":"Earth Story Time","d":"Read an Earth or nature book together, then ask your child to retell their favorite part. Retelling with details is the kindergarten skill hiding inside story time."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Earth month begins — little explorers start at home.","items":["Find land and water on any map or globe you pass this week.","Count 9 of anything blue or green.","Sort toy animals into land and water piles at cleanup time.","Read one nature story together and name your family’s favorite outdoor place."]}},{"label":"Week 2 — Reduce, Reuse, Recycle","days":[{"day":"Monday","focus":"The Three Rs","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Three R Words","d":"Teach the three big words — reduce, reuse, recycle — with hand motions your child invents. Then spot one example of each around the house. Big words make four-year-olds feel mighty."},{"t":"Everyone Helps Talk","d":"Talk about how your family, your street, and your town all take care of trash and recycling. Watch for the recycling truck and wave — those are Earth helpers."}]},{"day":"Tuesday","focus":"Recycle Relay","domains":["Physical Development","Mathematical Thinking"],"opts":[{"t":"Sorting Relay Race","d":"Set out clean recyclables and race to sort them — paper pile, plastic pile, metal pile. Count each pile at the finish and crown the biggest one."},{"t":"Nine-Item Pickup","d":"Challenge your child to find and put away 9 out-of-place things, counting down from nine as they go. Counting backward is a sneaky-hard skill worth practicing."}]},{"day":"Wednesday","focus":"Reuse Inventions","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Box Invention Lab","d":"Offer boxes, tubes, and masking tape and invent something new — a robot, a rocket, a home for a stuffed animal. When it flops, ask “What could we try instead?” and keep building."},{"t":"Junk-to-Art Gallery","d":"Turn clean recyclables into art — a lid mosaic, an egg-carton caterpillar — and host a tiny gallery showing. Reused materials make the point better than words do."}]},{"day":"Thursday","focus":"What Gets Reused","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Material Detectives","d":"Examine paper, plastic, and metal — bend each one, tap it, describe it. Which is strongest? Which crinkles? Sorting the world by material is early science thinking."},{"t":"Our Mess, Our Job","d":"After play, talk about responsibility while cleaning up together: “We made this mess, so we take care of it — just like people take care of the Earth.” Small habits, big idea."}]},{"day":"Friday","focus":"Y Is for Yes","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Y Day","d":"Practice the letter Y — yes, yellow, yo-yo, yawn — and make a giant Y with arms up wide and legs together. Write it big in the air, then small on paper."},{"t":"Try and Fly Words","d":"Collect words that end in y — try, fly, my, sky — and flap your arms once for each. Then read a favorite Bear Phonics decodable together. A book your child can read to you is worth celebrating."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Three-R week — small hands make a cleaner planet.","items":["Give your child the family recycling-sorter job this week.","Trace Y and y, then strike the big-arms Y pose.","Count how many items your family recycles in one day.","Reuse one big box as a reading fort — then read a story together inside it."]}},{"label":"Week 3 — Weather & Sky","days":[{"day":"Monday","focus":"Weather Watchers","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Window Weather Report","d":"Look out the window each morning and give a weather report — your child announces, you scribe one weather word on a simple journal page. Five days of watching makes a real weather scientist."},{"t":"Cloud Stories","d":"Lie back and watch the clouds, from the yard or the window, and tell what shapes you see. Describing clouds stretches vocabulary and imagination in one breath."}]},{"day":"Tuesday","focus":"Weather Moves","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Sun, Rain, Wind Dance","d":"Call out weather and move like it — stretch tall for sunshine, patter fingertips for rain, spin gently for wind, freeze for snow. Add music and it becomes a weather dance."},{"t":"Storm Drum Band","d":"Make a rainstorm with your bodies — rub palms, snap, pat knees, stomp — building loud and then fading soft. Conducting the storm puts your child in charge of big sounds."}]},{"day":"Wednesday","focus":"Graph the Weather","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Rain Jar Gauge","d":"Set a clear jar outside before the next rain and mark the water line with tape afterward. Compare the marks from storm to storm — which rain filled more? Your child is reading a measuring tool real scientists use."},{"t":"Puddle Measuring","d":"After rain, measure a puddle with heel-to-toe footsteps in the morning and again in the afternoon. Did it grow or shrink? Guess why. Coming back to check is the habit of a scientist."}]},{"day":"Thursday","focus":"Calm in Storms","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Storm-Calm Breathing","d":"Practice slow smell-the-flower, blow-the-cloud breaths for stormy days — loud thunder feels smaller with a calm body. Your Feelings Matter is a perfect read-along here if you have it."},{"t":"Weather Helpers","d":"Talk about the people who help us with weather — forecasters who warn us, crews who fix the lines, neighbors who share umbrellas. Helpers make storms less scary."}]},{"day":"Friday","focus":"Crescent Sky Art","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Crescent Moon Craft","d":"Paint or crayon a night sky with a crescent moon — April’s shape — and teal-blue swirls. Practice saying the word crescent; fancy words delight four-year-olds."},{"t":"Sky Watch Words","d":"Step outside at dusk and describe the sky together, then draw what you saw and label it with one word your child sounds out. Real observation makes real writers."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Weather week — keep one eye on the sky together.","items":["Give a morning weather report at breakfast every day.","Add to your weather graph and count the columns on Friday.","Look for the crescent moon at bedtime this week.","Practice storm-calm breathing once, so it is ready when thunder comes."]}},{"label":"Week 4 — Caring for Our Earth","days":[{"day":"Monday","focus":"Earth Promises","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"My Earth Promise","d":"Help your child finish the sentence “I care for the Earth by…” — you write the promise, they sign their name and decorate it. Post it low, where they can see it."},{"t":"Promise Keeper Check","d":"Each evening, ask how the promise went — lights off, water saved, trash sorted? Keeping a promise all week grows integrity, not just green habits."}]},{"day":"Tuesday","focus":"Clean-Up Crew","domains":["Physical Development","Social Studies"],"opts":[{"t":"Tidy the Earth Walk","d":"Take a family walk with a bag, and let your child spot litter while a grown-up with gloves collects it. Talk about why we leave places nicer than we found them."},{"t":"Earth Day Everywhere","d":"Talk about how kids all over the world help the Earth in April — planting trees, cleaning beaches, saving water. Your child is part of a planet-sized team."}]},{"day":"Wednesday","focus":"Count Green Deeds","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Green Deed Tally","d":"Tally every green deed on paper — a mark for lights off, water saved, litter binned — and count toward 9 by Friday. Watching the marks add up keeps the streak alive."},{"t":"Water Saver Count","d":"Count the seconds of water saved by turning off the tap during toothbrushing — can you beat yesterday’s number? Numbers plus habits, all before bedtime."}]},{"day":"Thursday","focus":"Why Plants Matter","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Thank a Tree","d":"Visit a tree and investigate — make a bark rubbing with crayon and paper, check its shade, look for who lives in it. Talk about what trees give us: air, shade, homes for animals."},{"t":"Water for Life","d":"Give a plant a drink together and talk about why every living thing needs water. Gratitude for ordinary things — water, sun, dirt — is stewardship at four."}]},{"day":"Friday","focus":"Earth Day Poster","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Earth Poster Project","d":"Make an Earth Day poster — a blue and green Earth, a crescent moon friend, and a message your child dictates while you letter it. Hang it in a window facing out."},{"t":"Review and Read","d":"Close the month with a letter check — Y plus favorites from the whole year — then read a favorite Bear Phonics decodable one last time and celebrate how far your reader has come."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Earth Day week — a promise, a poster, and proud helpers.","items":["Post your child’s signed Earth promise where everyone can see it.","Tally green deeds together and count them up Friday night.","Trace the number 9 and count 9 green things in the house.","Read together outside once this week — a blanket under a tree counts double."]}}]},"may":{"theme":"On the Move","weeks":[{"label":"Week 1 — Things That Go","days":[{"day":"Monday","focus":"Move Like Machines","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Vehicle Charades","d":"Take turns acting out a vehicle — chug like a train, soar like a plane — while the other person guesses. Say the word together and stretch out its first sound. Acting plus sounds locks new words in."},{"t":"Red Light Racers","d":"Play stop-and-go in the yard or hallway: green means zoom, red means freeze. Add yellow for slow motion. Stopping on cue is real self-control practice dressed up as play."}]},{"day":"Tuesday","focus":"Count the Wheels","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Ten-Car Parking Lot","d":"Draw ten numbered parking spaces on paper and let your child park toy cars, blocks, or bottle caps in order. Counting to ten while matching numerals is pure pre-K math."},{"t":"Wheel Count Sort","d":"Gather toy vehicles and sort them by how many wheels each one has — two, three, four, or more. Ask which pile has the most. Sorting by a rule builds thinking that lasts."}]},{"day":"Wednesday","focus":"How Wheels Roll","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"One Push Race","d":"Line up a ball, a toy car, and a crumpled paper ball, give each the same gentle push, and measure how far each travels in footsteps. Ask why the winner kept going. Fair tests — one push each — are how real scientists play."},{"t":"Round Things Race","d":"Roll a ball, a can, and a box across the floor and chase them down. Talk about why round things keep going. Big movement plus a why question is a great combo."}]},{"day":"Thursday","focus":"Vehicles That Help","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Helper Truck Talk","d":"Chat about fire trucks, garbage trucks, and ambulances — who drives them and how they help our neighborhood. Ask your child which helper they would be and why."},{"t":"Window Helper Watch","d":"Sit by the window or porch and watch for vehicles that help people. Wave, then say one kind thing about the worker inside. Gratitude is a habit you can grow."}]},{"day":"Friday","focus":"Build and Read","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Box Car Build","d":"Turn a cardboard box into a car with crayons, paper-plate wheels, and tape. Let your child decide every detail — it is their design, not yours. Then take it for a living-room drive."},{"t":"Things-That-Go Storytime","d":"Read a favorite vehicle book together, or this month's Bear Phonics decodable. Afterward, ask your child to retell what happened first, next, and last. Retelling is a kindergarten superpower."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in your pocket for a week of things that go.","items":["Narrate your drive: name every truck, bus, and bike you pass and clap its syllables.","Count to ten with wheels — how many wheels on two cars? Count and see.","Let your child be the red light at home: they call stop and go while you march.","Save one cardboard box this week — it is Friday's race car."]}},{"label":"Week 2 — On Land","days":[{"day":"Monday","focus":"Roads and Signs","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Tape Road Town","d":"Lay masking-tape roads across the floor and add paper signs your child draws. Talk about what each sign tells drivers to do. You have just built a town that runs on rules."},{"t":"Sign Shape Spotter","d":"On a walk or drive, spot signs and name their shapes — and hunt for a pentagon, the five-sided school-crossing sign. Shapes in the real world stick better than shapes on a page."}]},{"day":"Tuesday","focus":"Fast and Slow","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Near and Far Toss","d":"Toss a rolled-up sock at a laundry basket from close, then far. Measure each distance in footsteps and compare. Near, far, more, fewer — that is math talk in motion."},{"t":"Slow-Motion Relay","d":"Race across the room fast, then repeat in silly slow motion. Count how many seconds each trip takes. Feeling the difference between fast and slow makes the words real."}]},{"day":"Wednesday","focus":"Ramp Science","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Steeper Is Faster","d":"Prop a cardboard ramp on one book and roll a toy car, then add more books and try again. Ask your child to predict before each run. They are discovering that steeper means faster."},{"t":"Carpet vs. Tile","d":"Roll the same car down the same ramp onto carpet, then onto smooth floor. Which lets it travel farther, and why? Changing one thing at a time is how scientists think."}]},{"day":"Thursday","focus":"Retell the Trip","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Trip Tale Trio","d":"Ask your child to retell a real trip — even just to the grocery store — using first, next, and last. Then let them draw their favorite part and write their name on it."},{"t":"Buckle-Up Buddies","d":"Talk through your family's travel rules: buckle up, hold hands in parking lots, wait calmly. Let your child buckle in a stuffed animal and explain the rules to it. Teaching it back means they own it."}]},{"day":"Friday","focus":"Trains and Tracks","domains":["Creative Expression","Mathematical Thinking"],"opts":[{"t":"Pattern Train","d":"Cut or tear paper train cars and line them up in a color pattern — red, blue, red, blue. Ask what comes next. If you have Freight Train by Donald Crews, read it together first."},{"t":"Ten-Box Express","d":"Line up ten boxes, blocks, or couch cushions into a train and count each car as your child climbs aboard. Then count backward from ten as the train unloads. All aboard for number ten."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A little land travel for your week together.","items":["Hunt for one pentagon sign this week — five sides, usually near a school.","At dinner, take turns retelling today with first, next, and last.","Leave the tape roads down a few days; small towns grow with time.","Practice the parking-lot rule every trip: hand in hand until the sidewalk."]}},{"label":"Week 3 — On Water & Air","days":[{"day":"Monday","focus":"Float or Sink","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Orange Peel Puzzle","d":"Float an orange in a bowl of water, then peel it and try again — surprise, it sinks. The peel holds tiny air pockets, like a little life jacket. Stay within arm's reach and let your child guess the why before you tell."},{"t":"Foil Boat Cargo","d":"Shape a square of foil into a little boat and count how many dry beans or buttons it holds before it sinks. Try a new boat shape and beat the record. Stay right beside the water together."}]},{"day":"Tuesday","focus":"Paper Pilots","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Paper Plane Trials","d":"Fold paper airplanes together and launch them down the hallway, measuring each flight in footsteps. Let your child decorate theirs first — pilots name their planes."},{"t":"Blow-Boat Regatta","d":"Fold a simple paper boat and race it across a baking pan of water by blowing through a straw, staying within arm's reach. All that huffing is great mouth-muscle work for speech."}]},{"day":"Wednesday","focus":"Traveling Far","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Map Voyage","d":"Open a map or globe — even a map on a cereal box or phone — and ask where your child would sail or fly. Trace the route with a finger and name what you would pack."},{"t":"Postcard From Above","d":"Draw a postcard from an imaginary plane ride: what do you see out the window? You write their dictated message, and they sign their name. Name writing counts every single time."}]},{"day":"Thursday","focus":"Brave New Tries","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Brave Means Trying","d":"Talk about this month's big idea: brave means trying even when it is tricky. Let your child pick one tricky thing to try today, and cheer the trying, not just the result."},{"t":"Try-Again Plane","d":"When a paper plane crash-lands, resist fixing it yourself. Ask, what could we change? Fold one thing differently and test again. Bouncing back from a flop is the real lesson."}]},{"day":"Friday","focus":"Row and Read","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Laundry Basket Boat","d":"Climb your child into a laundry basket boat and row with wooden-spoon oars while you sing Row, Row, Row Your Boat. Make up new verses — row to Grandma's, row to the moon."},{"t":"Water Word Reading","d":"Read together tonight and listen for water and sky words — boat, wave, cloud, fly. Every time one appears, your child makes a splash motion. Listening for words builds sharp reading ears."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Boats, planes, and brave tries — right from your kitchen.","items":["Water play rule of the week: always within arm's reach, always together.","Keep a brave-try list on the fridge and add one trying moment a day.","Bath time is float-or-sink time — two new items per bath.","Fold one paper plane to keep by the door for rainy-day hallway flights."]}},{"label":"Week 4 — How I Move","days":[{"day":"Monday","focus":"Action Words","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Verb Freeze Dance","d":"Call out action words — hop, spin, stomp, wiggle — and freeze when the word stops. Then swap roles and let your child call the verbs. Naming a move while doing it doubles the learning."},{"t":"Alphabet Actions","d":"Review letters A to Z by matching moves to sounds: jump for J, march for M, zoom for Z. Say each letter sound as you move. Whole-body review beats flashcards every time."}]},{"day":"Tuesday","focus":"Count My Moves","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Jump and Graph","d":"Count jumps, hops, and toe-touches — aim for ten of each — and stack one block per move into a simple graph. Which move got the tallest tower? Reading the graph together is the math payoff."},{"t":"Family Move Survey","d":"Have your child ask each family member their favorite way to move, then make a tally mark for each answer. Count the marks and announce a winner. That is real data from a real researcher."}]},{"day":"Wednesday","focus":"Muscle Detectives","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Strong Muscle Hunt","d":"Squeeze a fist and feel the arm muscle bump up, then hunt for the muscles that hop, kick, and tiptoe. Which body part works hardest in a crab-walk? Bodies are the best science lab you own."},{"t":"Pentagon Hopscotch","d":"Tape or chalk a big five-sided pentagon on the floor and hop from corner to corner, counting all five sides. Balance on one foot at each point. Shape review plus balance in one game."}]},{"day":"Thursday","focus":"Getting to School","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"My Route Map","d":"Draw a simple map of how your child gets to school — home, the big turn, the school door. Let them add landmarks they remember. Maps help children see their place in the neighborhood."},{"t":"I Can Move Show","d":"Host a thirty-second talent show where your child performs a move they have mastered this year and takes a bow. Say back exactly what you saw. Being truly seen builds confidence that lasts."}]},{"day":"Friday","focus":"Dance and Paint","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Rainbow Movement Art","d":"Play a favorite song, dance with scarves or dish towels, then paint or color how the music felt using every rainbow color you can find. Moving first makes the art bolder."},{"t":"Storybook Warm-Up","d":"Read together, then act the story out with your whole bodies — creep like the fox, leap like the frog. For a challenge, try this month's Bear Phonics reader and act out each page."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A week of wiggles that are secretly building a reader.","items":["Do ten of something daily — ten jumps, ten claps, ten toe-touches — and count out loud.","Play alphabet actions in waiting rooms: whisper a letter sound, do its tiny move.","Cross the midline: touch right hand to left knee ten times — it wires reading readiness.","End the week with a family dance party and one big bow each."]}}]},"jun":{"theme":"Sun, Sand & Splash","weeks":[{"label":"Week 1 — At the Beach","days":[{"day":"Monday","focus":"Beach Words","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Beach Word Pictures","d":"Say beach words together — sand, shell, wave, crab — and let your child draw each one and label it with its first letter. Drawing a word plants it deeper than just hearing it."},{"t":"Salt Tray Writing","d":"Pour a thin layer of salt or sugar onto a baking tray and let your child write letters and their whole name with one finger, then shake to erase. It feels like beach sand and builds real handwriting."}]},{"day":"Tuesday","focus":"Count and Sort","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Eleven Treasures","d":"Collect eleven shells, pebbles, or pasta pieces and count them slowly, touching each one. Then split them into groups and count again. Eleven is this month's number — make it famous at your house."},{"t":"Sort the Shore","d":"Spread out your beachy collection and sort it by size, then re-sort by color or shape. Ask your child to explain their rule. Explaining a sort is thinking out loud, and that is the goal."}]},{"day":"Wednesday","focus":"Wet and Dry","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Castle Test Lab","d":"Try packing a cup with dry sand or dirt, then with damp — which holds its castle shape when you flip it? Ask why before you test. One spray bottle turns the backyard into a lab."},{"t":"Hot Sand Tiptoe","d":"Pretend the floor is hot sand and tiptoe across pillow stepping-stones to reach the beach towel. Add a wobbly balance pose on each pillow. Silly, sweaty, and great for growing balance."}]},{"day":"Thursday","focus":"Beach Safety","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Water Watcher Badge","d":"Talk about your family's water rules — a grown-up always watching, always within arm's reach — and make a paper Water Watcher badge for the adult in charge. Rules feel fair when kids help make the badge."},{"t":"Wave Breathing","d":"Practice calm-down breathing like the ocean: breathe in as the wave rises, out as it rolls to shore. Do five slow waves together. This is the tool you will both reach for on hard days."}]},{"day":"Friday","focus":"Shore Stories","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Shell Collage","d":"Glue shells, torn paper, or dry pasta onto cardboard to make a beach scene. Ask your child to tell you the story inside the picture while you write one line of it underneath."},{"t":"Ocean Read-Aloud","d":"Read a beach or ocean book together — or this month's Bear Phonics decodable — and retell it with first, next, and last. Retelling is exactly what kindergarten teachers hope to see."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A beach week, no beach required.","items":["Count to eleven everywhere — stairs, crackers, seagulls in a picture book.","Keep the salt tray on the counter for one name-writing a day.","Say the water rule until it is automatic: a grown-up always watching, always within arm's reach.","Practice wave breathing at bedtime — five slow waves and lights out."]}},{"label":"Week 2 — In the Water","days":[{"day":"Monday","focus":"Pour and Measure","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Cup Count Pour","d":"At the sink or a dishpan, count how many small cups it takes to fill the big pitcher. Guess first, then test, staying within arm's reach. Guess-then-check is the whole scientific method in miniature."},{"t":"Water Line Marks","d":"Tape a strip up the side of a clear container and mark the water line each time your child adds a cup. Watch the line climb. They are reading a measuring tool they built themselves."}]},{"day":"Tuesday","focus":"Swim Moves","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Dry-Land Swim","d":"Lie tummy-down on a blanket and practice big swim arms and flutter kicks while you count strokes together. Dry-land practice builds the arm strength and confidence real swimming needs."},{"t":"Teamwork Water Carry","d":"Carry one cup of water across the yard together, each holding one side, without spilling. Then try a bowl. Cooperation is this month's character focus — and spills are half the fun."}]},{"day":"Wednesday","focus":"Float Predictions","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Predict Then Splash","d":"Line up eleven small items and have your child predict sink or float before each test, staying within arm's reach of the water. Count how many predictions came true. Wrong guesses teach the most."},{"t":"Build a Floater","d":"Challenge your child to build something that floats from kitchen scraps — a lid, foil, a sponge. Test, tweak, and test again. Sticking with a tricky build is the skill underneath all school skills."}]},{"day":"Thursday","focus":"Water Helpers","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Lifeguard Story Talk","d":"Read an ocean or pool book together, then talk about lifeguards and swim teachers — the helpers who keep swimmers safe. Ask your child what a lifeguard watches for."},{"t":"Letter Fishing","d":"Write letters on paper fish and scatter them on the floor. Your child fishes one out, names the letter, and says its sound — a splashy A-to-Z review. Add a paper-towel-tube fishing rod for flair."}]},{"day":"Friday","focus":"Fish Art","domains":["Creative Expression","Mathematical Thinking"],"opts":[{"t":"Handprint Fish","d":"Paint your child's palm aqua — this month's color — and press a handprint fish onto paper, adding an eye and bubbles. Make a whole school of fish and count them as you go."},{"t":"Pattern Waves","d":"Draw wave stripes across the page in a repeating pattern — aqua, white, aqua, white — and ask what comes next. Then hide eleven tiny fish in the waves for a count-and-find."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Turn every splash into science this week.","items":["Bath night is lab night: predict sink or float before every toy goes in.","Let your child pour at dinner — small pitcher, steady hands, real measuring.","Do one teamwork job a day together and name it out loud: we cooperated.","Keep the letter fish in a zip bag for five-minute fishing rounds."]}},{"label":"Week 3 — Sun & Sky","days":[{"day":"Monday","focus":"Shadow Science","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Shadow Measuring","d":"Trace your child's shadow with chalk in the morning, then again in the afternoon, and measure both with footsteps. Which is longer? The sun moved — and your child just collected the evidence."},{"t":"Cloud Count Blanket","d":"Lie on a blanket, count the clouds, and name the shapes you see in them — a circle, a triangle, maybe a dragon. Shape review works best flat on your back."}]},{"day":"Tuesday","focus":"Sun Safety","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Sun-Safe Chart","d":"Make a picture chart of your family's sun rules — hat, sunscreen, water bottle, shade breaks — with your child drawing each picture and writing the first letter. Kids follow charts they helped make."},{"t":"Shade Spotter","d":"Walk the yard or park and find the three best shady spots, then rank them from coolest to warmest. Talk about why shade feels cooler. New words like shade and shelter ride along free."}]},{"day":"Wednesday","focus":"Freeze and Chase","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Sunshine Freeze Tag","d":"Play chase where the tagger is the sun: when tagged, freeze like a statue until a friend melts you with a tap. Freezing mid-run takes serious body control — that is the workout inside the game."},{"t":"Shadow Copycat","d":"Stand in the sun and strike poses while your child copies your shadow exactly, then trade jobs. Try one-foot balances and tricky arm shapes. Watching and matching builds focus."}]},{"day":"Thursday","focus":"Calm in Shade","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Shade Rest Ritual","d":"Spread a blanket in the shade for a five-minute quiet rest with slow belly breaths. Ask what your child notices with eyes closed — birds, breeze, a far-off dog. Rest is a skill, and summer is for practicing it."},{"t":"Aqua Sky Art","d":"Draw or chalk a big sky picture using aqua and every blue you own — sun, clouds, birds, maybe a kite. Ask your child to tell you about it and write their title at the top."}]},{"day":"Friday","focus":"Day and Night","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Read in the Shade","d":"Take today's read-aloud outside to your shady spot — a sunny-day book or this month's Bear Phonics reader. Ask your child to point out any words they can read themselves."},{"t":"Day Sky, Night Sky","d":"Fold a paper in half and draw the day sky on one side and the night sky on the other. Talk about what changes and what stays. Comparing two pictures is comparing two ideas."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Sunshine learning with shade breaks built in.","items":["Let your child lead the sun-safe chart every morning: hat, sunscreen, water.","Check your shadow at two different times one day — long or short?","Take one book outside this week; shade reading feels like a treat.","Add a water-bottle count: eleven big sips after playing hard."]}},{"label":"Week 4 — Summer Play","days":[{"day":"Monday","focus":"Backyard Games","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Family Relay","d":"Set up a simple relay — run to the fence, spin twice, run back — and cheer every runner by name, fastest or not. Make sure everyone gets a turn to pick the silly move."},{"t":"Sock Ball Keep-Up","d":"Bat a rolled-sock ball back and forth and count how many hits before it drops, then try to beat your record together. A shared goal turns a game into teamwork."}]},{"day":"Tuesday","focus":"Graph Our Fun","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Favorite Play Graph","d":"Survey the family: sprinkler, bikes, or playground? Stack one block per vote and read the graph together. Which play won, and by how many? That is data your child collected themselves."},{"t":"Summer Story Stretch","d":"Ask your child to tell about a summer adventure using first, next, and last while you write it down word for word. They illustrate and sign their name — a real author's page."}]},{"day":"Wednesday","focus":"Water Why","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Thirsty Celery Test","d":"Stand a celery stalk in a cup of water with a drop of food coloring and check it over two days. Where did the color go? Talk about why our bodies need water on hot days too."},{"t":"Ice Melt Race","d":"Place one ice cube in the sun and one in the shade and predict which melts first. Check every few minutes and count the checks. Waiting and watching is how patient scientists are made."}]},{"day":"Thursday","focus":"Summer Everywhere","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Summer Somewhere Else","d":"Talk about how kids play in summer around the world — beaches, mountains, big city sprinklers — and find one place on a map. Ask which summer your child would visit."},{"t":"Memory Painting","d":"Paint or color a favorite summer memory so far, big and bold. While they work, ask questions about the day they chose. Art plus talk is how young memories become stories."}]},{"day":"Friday","focus":"Share and Read","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Everyone Plays Game","d":"Invent a family game together with one rule that cannot change: everyone gets a turn. Let your child explain the rules to each player. Including everyone is the lesson hiding inside."},{"t":"Book Picnic","d":"Spread a blanket, pack a snack, and read two books picnic-style — maybe Your Feelings Matter or a favorite summer story. Let your child hold the book and turn every page."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Wrap up the month with play that includes everybody.","items":["Keep the everyone-gets-a-turn rule for all games this week — kids will hold you to it.","Check the celery experiment together at breakfast; slow science is still science.","Retell one summer adventure at bedtime with first, next, and last.","Plan one book picnic — even the living-room floor counts."]}}]},"jul":{"theme":"Imagination Station","weeks":[{"label":"Week 1 — Once Upon a Time","days":[{"day":"Monday","focus":"Act It Out","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Story Theater","d":"Pick a favorite story and act it out with your whole bodies while you narrate — stomp the bridge, huff at the brick house. Acting a story out is retelling with muscles, and it sticks."},{"t":"Walk-and-Retell","d":"On a walk, ask your child to retell last night's book using first, next, and last — one part per block. By the time you are home, they have told the whole tale."}]},{"day":"Tuesday","focus":"Story Order","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Sequence Cards","d":"Have your child draw three moments from a story on three papers, shuffle them, and put them back in order — first, next, last. Ordering a story is the same thinking as ordering numbers."},{"t":"Character Tally","d":"During tonight's book, make a tally mark for every character who appears and count the marks at the end — can you find twelve? Twelve is this month's number, so give it the spotlight."}]},{"day":"Wednesday","focus":"Real or Pretend","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Real vs. Pretend","d":"Name things from stories — a talking wolf, a red truck, a flying carpet — and have your child sort them: could that happen for real? Sorting real from pretend is early critical thinking."},{"t":"Feelings in Stories","d":"Reread a favorite book and pause to ask how each character feels and why — Your Feelings Matter is perfect for this. Naming feelings in stories makes them easier to name in real life."}]},{"day":"Thursday","focus":"Tales Everywhere","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Story From Far Away","d":"Share a folktale from another country or a story from your own family's past — where Grandma grew up, how you got your name. Every family carries stories worth passing down."},{"t":"Story Stones","d":"Draw little pictures on paper circles — a sun, a dog, a boat — drop them in a cup, pull out three, and weave a brand-new tale using all of them. Trade turns being the storyteller."}]},{"day":"Friday","focus":"Author Day","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"My Own Book","d":"Fold two papers into a little book and let your child draw the story while dictating the words for you to write. They sign their name on the cover, because authors always do."},{"t":"Read and Retell","d":"Read together tonight — a library favorite or this month's Bear Phonics decodable — then hand the book over and let your child read the pictures back to you in their own words."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A week of stories told, sorted, and starred in.","items":["Ask first-next-last after every book this week; it takes one extra minute.","Keep the story stones in a cup on the table for waiting-time tales.","Play real-or-pretend in the car — one silly idea per red light.","Display the homemade book where guests will ask about it."]}},{"label":"Week 2 — Make-Believe & Dress-Up","days":[{"day":"Monday","focus":"Character Moves","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Move Like Someone","d":"Call out characters and move like them — stomp like a giant, tiptoe like a mouse, glide like a queen. Then let your child call the characters while you do the moving."},{"t":"Costume Box Raid","d":"Fill a box with old hats, scarves, big shirts, and towels, and let your child build a costume from scratch. Announce the character with a grand introduction. No store costume beats a towel cape."}]},{"day":"Tuesday","focus":"Pretend Jobs","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Home Restaurant","d":"Open a pretend restaurant: your child scribble-writes the menu, takes your order, and serves invisible spaghetti. All that pretend writing and back-and-forth talk is genuine literacy work."},{"t":"Helper Role-Play","d":"Take turns playing community helpers — doctor, firefighter, mail carrier — with real dialogue: what does the doctor ask first? Pretend jobs teach how our neighborhood works."}]},{"day":"Wednesday","focus":"What Could This Be","domains":["Approaches to Learning","Scientific Inquiry"],"opts":[{"t":"Not a Box","d":"Read Not a Box by Antoinette Portis if you have it, then hand your child a real box and ask what it could become. Rocket, cave, turtle shell — follow their lead and play it out."},{"t":"Mystery Object Ideas","d":"Hold up a spoon or a colander and brainstorm twelve things it could be — a microphone, a helmet, an oar. Count each idea on your fingers. Flexible thinking grows with silly practice."}]},{"day":"Thursday","focus":"I Can Be","domains":["Social & Emotional Development","Mathematical Thinking"],"opts":[{"t":"I Can Be Anything","d":"Stand at the mirror and let your child announce who they will be today — astronaut, baker, teacher — and act one minute of that life. Saying it out loud builds the belief underneath it."},{"t":"Prop Shop Count","d":"Set up a pretend shop with dress-up props priced one to twelve, and pay with buttons or paper coins, counting each one out. Playing store is counting practice in disguise."}]},{"day":"Friday","focus":"Puppet Show","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Sock Puppet Pal","d":"Turn an old sock into a puppet with marker eyes or paper ears, then let it introduce itself — name, favorite food, biggest dream. A puppet often says things a shy speaker will not."},{"t":"Puppet Storytime","d":"Let the new puppet join tonight's read-aloud and repeat favorite lines in a funny voice. Ask the puppet questions about the story and let your child answer for it. Comprehension, but make it giggly."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Dress-up is deep work this week — protect the playtime.","items":["Leave the costume box out all week; five-minute transformations count.","Order breakfast from the home restaurant one morning and tip in buttons.","Ask at dinner: what did the box become today?","Let the sock puppet handle one tricky moment, like tooth-brushing."]}},{"label":"Week 3 — Art & Music","days":[{"day":"Monday","focus":"Dance Styles","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Music Mix Dance","d":"Play three very different songs — something slow, something bouncy, something grand — and dance the way each one feels. Ask which was your child's favorite and why."},{"t":"Scarf Symphony","d":"Hand out scarves or dish towels and swirl them high, low, fast, and slow to the music. Big arm circles cross the midline, which quietly strengthens reading readiness."}]},{"day":"Tuesday","focus":"Pattern Beats","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Clap the Pattern","d":"Clap a pattern — clap, clap, stomp — and have your child echo it, then extend it. Trade jobs and let them invent one for you. Patterns in sound become patterns in math."},{"t":"Pattern Border Art","d":"Draw a repeating border around a page — purple, white, purple, white — using this month's color, and ask what comes next before each mark. Then fill the middle with anything at all."}]},{"day":"Wednesday","focus":"Sound Science","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Kitchen Band Lab","d":"Tap pots, bowls, and cups with a wooden spoon and sort the sounds: high or low, loud or soft. Ask why the big pot sounds different from the little cup. That is sound science, right in your kitchen."},{"t":"Art Gallery Talk","d":"Spread out recent artwork and interview the artist: what did you make, how did you do it, what was hardest? Write one quote under each piece. Describing their work grows big vocabulary."}]},{"day":"Thursday","focus":"Art Around World","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Music From Far Away","d":"Listen to a song from another country and move however it tells you to. Find the country on a map together. Music is a passport that fits in your pocket."},{"t":"Paint a Feeling","d":"Ask your child to pick a feeling — happy, grumpy, excited — and paint it using only colors, no pictures. Talk about why they chose each color. Art gives feelings somewhere safe to go."}]},{"day":"Friday","focus":"Gallery Day","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Home Art Show","d":"Tape the week's art to a wall, make tickets, and host a family art show where the artist presents each piece. Clap generously. Being taken seriously as an artist builds a confident speaker."},{"t":"Storybook Soundtrack","d":"Read a book together — this month's Bear Phonics reader works beautifully — and add sound effects with your kitchen instruments at just the right moments. Listening for the moment is close listening."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Fill the house with art, music, and purple this week.","items":["Keep a family dance break on call for cranky afternoons — one song fixes a lot.","Hunt for purple all week and count how many things you find.","Echo-clap patterns while waiting anywhere: you clap, they copy, then swap.","Save one wall spot as the gallery and rotate the art on Fridays."]}},{"label":"Week 4 — Dream Big","days":[{"day":"Monday","focus":"Hero Training","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Hero Obstacle Course","d":"Build a course from cushions and chairs — leap the lava, crawl the tunnel, balance the beam — and cheer your hero through by name. Finish with a superhero landing pose."},{"t":"Cape of Confidence","d":"Tie on a towel cape and take turns saying strong sentences: I can climb high, I can learn hard things. Say yours too — kids believe brave words more when grown-ups wear capes."}]},{"day":"Tuesday","focus":"When I Grow Up","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Grown-Up Interview","d":"Let your child interview you or a relative: what is your job, what did you dream of as a kid? They will discover grown-ups were once four years old with big plans too."},{"t":"Dream Job Page","d":"Have your child draw themselves all grown up while dictating the sentence, when I grow up I will… — then they sign their name underneath. Save this one forever."}]},{"day":"Wednesday","focus":"Inventor Lab","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Junk Drawer Invention","d":"Set out boxes, tubes, tape, and lids and challenge your child to invent something brand new. Ask what it does and how it works. Inventors imagine first, then build — just like the pros."},{"t":"Fix-It Challenge","d":"Read The Most Magnificent Thing by Ashley Spires if you have it, then pick a tiny household problem — toys spilling, socks escaping — and invent a fix together. Test it, tweak it, try again."}]},{"day":"Thursday","focus":"Plan the Dream","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Blueprint Drawing","d":"Have your child draw a plan for their invention or dream fort, then count the pieces it needs — aiming for twelve. Real builders draw before they build, and now your child does too."},{"t":"Dream Mural","d":"Tape a big piece of paper to the wall and fill it with every dream your child can draw — places to go, things to become. Add purple wherever it fits and give the mural a grand title."}]},{"day":"Friday","focus":"Ideas Matter","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Idea Cheer Circle","d":"Sit in a family circle where each person shares one big idea and everyone cheers it — no fixing, no judging, just cheering. My ideas matter is the sentence this whole month was building."},{"t":"Dream Journal Night","d":"Start a bedtime dream journal: your child draws one big dream, writes their name, and you read one dream-big story together before lights out. Small ritual, mighty message."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Send the month out with big dreams said out loud.","items":["Ask what do you want to be today? each morning — accept dragon as an answer.","Keep invention supplies in one bin: boxes, tape, tubes, lids.","Cheer one idea per person at dinner, kids and grown-ups alike.","Tuck the dream-job drawing somewhere safe — future-you will thank you."]}}]}};